window.PACTO.acts["reg-2018-1861"]={"label": "REGOLAMENTO (UE) 2018/1861 DEL PARLAMENTO EUROPEO E DEL CONSIGLIO", "short": "Reg. 2018/1861", "file": "ext-reg-2018-1861.html", "external": true, "version": "consolidato 2021-08-03", "eurlex": "https://eur-lex.europa.eu/eli/reg/2018/1861/oj/ita", "articles": {"1": {"label": "Articolo 1", "heading": "Scopo generale del SIS", "anchor": "art_1", "frags": [[null, "<p class=\"norm\">Scopo del SIS è assicurare un elevato livello di sicurezza nello spazio di libertà, sicurezza e giustizia dell'Unione, inclusi il mantenimento della sicurezza pubblica e dell'ordine pubblico e la salvaguardia della sicurezza nel territorio degli Stati membri, e garantire l'applicazione delle disposizioni della parte terza, titolo V, capo 2, del TFUE relative alla circolazione delle persone in detto territorio, avvalendosi delle informazioni trasmesse mediante tale sistema.</p>"]]}, "2": {"label": "Articolo 2", "heading": "Oggetto", "anchor": "art_2", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il presente regolamento stabilisce le condizioni e le procedure applicabili all'inserimento e al trattamento nel SIS delle segnalazioni riguardanti cittadini di paesi terzi e allo scambio di informazioni supplementari e dati complementari ai fini del respingimento e del rifiuto di soggiorno nel territorio degli Stati membri.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il presente regolamento contempla anche disposizioni sull'architettura tecnica del SIS, sulle competenze degli Stati membri e dell'agenzia dell'Unione europea per la gestione operativa dei sistemi IT su larga scala nello spazio di libertà, sicurezza e giustizia («eu-LISA»), sulle regole sul trattamento dei dati, sui diritti delle persone interessate e sulla responsabilità.</div>\n</div>"]]}, "3": {"label": "Articolo 3", "heading": "Definizioni", "anchor": "art_3", "frags": [[null, "<p class=\"norm\">Ai fini del presente regolamento s'intende per:</p>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">1)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«segnalazione» : un insieme di dati inseriti nel SIS che permette alle autorità competenti di identificare una persona al fine di intraprendere un'azione specifica;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">2)</p>\n</td>\n<td valign=\"top\">\n<p class=\"normal\">«informazioni supplementari» : </p>\n<p class=\"norm\">le informazioni non facenti parte dei dati di segnalazione conservati nel SIS ma connesse alle segnalazioni inserite nel SIS, che devono essere scambiate tramite gli uffici SIRENE:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per permettere agli Stati membri di consultarsi o informarsi a vicenda quando introducono una segnalazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">in seguito a un riscontro positivo (hit) al fine di consentire l'azione appropriata;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">quando non è possibile procedere all'azione richiesta;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">con riguardo alla qualità dei dati SIS;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">con riguardo alla compatibilità e alla priorità delle segnalazioni;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">con riguardo ai diritti di accesso;</p>\n</div>\n</div>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">3)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«dati complementari» : i dati memorizzati nel SIS e connessi alle segnalazioni inserite nel SIS, che devono essere immediatamente disponibili per le autorità competenti nei casi in cui una persona i cui dati sono stati inseriti nel SIS sia localizzata grazie all'interrogazione del SIS;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">4)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«cittadino di paese terzo» : chi non è cittadino dell'Unione ai sensi dell'articolo 20, paragrafo 1, TFUE, a eccezione di chi, in virtù di accordi conclusi tra l'Unione, o tra l'Unione e i suoi Stati membri, da un lato, e paesi terzi, dall'altro, beneficia di diritti in materia di libera circolazione equivalenti a quelli dei cittadini dell'Unione;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">5)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«dati personali» : dati personali quali definiti all'articolo 4, punto 1), del regolamento (UE) 2016/679;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">6)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«trattamento dei dati personali» : qualsiasi operazione o insieme di operazioni, compiute con o senza l'ausilio di processi automatizzati e applicate a dati personali o insiemi di dati personali, come la raccolta, la memorizzazione, la registrazione, l'organizzazione, la strutturazione, la conservazione, l'adattamento o la modifica, l'estrazione, la consultazione, l'uso, la comunicazione mediante trasmissione, diffusione o qualsiasi altra forma di messa a disposizione, il raffronto o l'interconnessione, la limitazione, la cancellazione o la distruzione;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">7)</p>\n</td>\n<td valign=\"top\">\n<p class=\"normal\">«corrispondenza» : </p>\n<p class=\"norm\">il verificarsi, nell'ordine, di quanto segue:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un utente finale ha effettuato un'interrogazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'interrogazione ha rivelato la presenza di una segnalazione inserita nel SIS da un altro Stato membro; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i dati relativi alla segnalazione nel SIS corrispondono ai dati dell'interrogazione;</p>\n</div>\n</div>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">8)</p>\n</td>\n<td valign=\"top\">\n<p class=\"normal\">«riscontro positivo (hit)» : </p>\n<p class=\"norm\">una corrispondenza che soddisfi i seguenti criteri:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è stata confermata da:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'utente finale; oppure,</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'autorità competente conformemente alle procedure nazionali qualora la corrispondenza in questione sia basata sul raffronto di dati biometrici;</p>\n</div>\n</div>\n<p class=\"list\">e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sono richieste ulteriori azioni;</p>\n</div>\n</div>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">9)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«Stato membro segnalante» : lo Stato membro che ha inserito la segnalazione nel SIS;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">10)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«Stato membro di rilascio» : lo Stato membro che esamina la possibilità di rilasciare o di prorogare un permesso di soggiorno o un visto per soggiorno di lunga durata o che lo ha rilasciato o prorogato, ed è coinvolto nella procedura di consultazione con un altro Stato membro;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">11)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«Stato membro di esecuzione» : lo Stato membro che intraprende o ha intrapreso l'azione richiesta in seguito a un riscontro positivo (hit);</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">12)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«utente finale» : membro del personale di un'autorità competente autorizzato ad interrogare direttamente il CS-SIS, l'N.SIS o una loro copia tecnica;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">13)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«dati biometrici» : i dati personali ottenuti da un trattamento tecnico specifico relativi alle caratteristiche fisiche o fisiologiche di una persona fisica che ne consentono o confermano l'identificazione univoca, vale a dire fotografie, immagini del volto e dati dattiloscopici;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">14)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«dati dattiloscopici» : dati relativi alle impronte digitali e alle impronte palmari che, per il loro carattere di unicità e i punti caratteristici che contengono, permettono confronti precisi e irrefutabili sull'identità di una persona;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">15)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«immagine del volto» : le immagini digitali del volto caratterizzate da sufficiente risoluzione e qualità dell'immagine per essere utilizzate in un raffronto biometrico automatizzato;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">16)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«rimpatrio» : il rimpatrio quale definito nell'articolo 3, punto 3), della direttiva 2008/115/CE;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">17)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«divieto d'ingresso» : il divieto d'ingresso quale definito nell'articolo 3, punto 6), della direttiva 2008/115/CE;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">18)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«reati di terrorismo» : i reati previsti dal diritto nazionale di cui agli articoli da 3 a 14 della direttiva (UE) 2017/541 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">1</span>\n) o equivalenti a uno di tali reati per gli Stati membri che non sono vincolati da detta direttiva;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">19)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«permesso di soggiorno» : il permesso di soggiorno quale definito nell'articolo 2, punto 16), del regolamento (UE) 2016/399 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">2</span>\n);</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">20)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«visto per soggiorno di lunga durata» : il visto per soggiorno di lunga durata di cui all'articolo 18, paragrafo 1, della convenzione d'applicazione dell'accordo di Schengen;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">21)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«minaccia per la salute pubblica» : minaccia per la salute pubblica quale definita nell'articolo 2, punto 21), regolamento (UE) 2016/399;</p>\n</td>\n</tr>\n</table>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">22)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«ESP» : il portale di ricerca europeo istituito dall'articolo 6, paragrafo 1, del regolamento (UE) 2019/817 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">3</span>\n);</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">23)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«BMS comune» : il servizio comune di confronto biometrico istituito dall'articolo 12, paragrafo 1, del regolamento (UE) 2019/817;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">24)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«CIR» : l'archivio comune di dati di identità istituito dall'articolo 17, paragrafo 1, del regolamento (UE) 2019/817;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">25)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«MID» : il rilevatore di identità multiple istituito dall'articolo 25, paragrafo 1, del regolamento (UE) 2019/817.</p>\n</td>\n</tr>\n</table>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "4": {"label": "Articolo 4", "heading": "Architettura tecnica e modalità operative del SIS", "anchor": "art_4", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il SIS consta di:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un sistema centrale («SIS centrale») costituito da:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un'unità di supporto tecnico («CS-SIS») che contiene una banca dati, la «banca dati del SIS», e che include un CS-SIS di riserva,</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un'interfaccia nazionale uniforme («NI-SIS»);</p>\n</div>\n</div>\n</div>\n</div>\n<p class=\"modref\">\n▼M1\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un sistema nazionale (N.SIS) in ciascuno Stato membro, composto dei sistemi di dati nazionali che comunicano con il SIS centrale, e che includa almeno un N.SIS di riserva (backup site) nazionale o condiviso;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un'infrastruttura di comunicazione fra il CS-SIS, il CS-SIS di riserva e l'NI-SIS («infrastruttura di comunicazione») che fornisce una rete virtuale cifrata dedicata ai dati SIS e provvede allo scambio di dati tra gli uffici SIRENE di cui all'articolo 7, paragrafo 2; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un'infrastruttura di comunicazione sicura tra il CS-SIS e le infrastrutture centrali dell'ESP, del BMS comune e del MID.</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n</div>\n</div>"], [null, "<p class=\"norm\">Un N.SIS di cui alla lettera b) può contenere un archivio di dati («copia nazionale»), contenente a sua volta una copia completa o parziale della banca dati del SIS. Due o più Stati membri possono creare una copia condivisa in uno dei loro N.SIS, che può essere usata congiuntamente dagli Stati membri in questione. Tale copia condivisa è considerata la copia nazionale di ciascuno di tali Stati membri.</p>"], [null, "<p class=\"norm\">Un N.SIS di riserva condiviso di cui alla lettera b) può essere usato congiuntamente da due o più Stati membri. In tal caso, l'N.SIS di riserva è considerato l'N.SIS di riserva di ciascuno di tali Stati membri. L'N.SIS e la sua copia di riserva possono essere usati simultaneamente per garantire agli utenti finali una disponibilità ininterrotta.</p>"], [null, "<p class=\"norm\">Gli Stati membri che intendono creare una copia condivisa o un N.SIS di riserva condiviso da utilizzare congiuntamente definiscono le rispettive responsabilità in un accordo scritto. Essi notificano il proprio accordo alla Commissione.</p>"], [null, "<p class=\"norm\">L'infrastruttura di comunicazione sostiene e contribuisce a garantire la disponibilità ininterrotta del SIS. Essa comprende percorsi ridondanti e separati per le connessioni tra il CS-SIS e il CS-SIS di riserva, oltre che percorsi ridondanti e separati per le connessioni tra ciascun punto di accesso nazionale alla rete SIS e il CS-SIS e il CS-SIS di riserva.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli Stati membri inseriscono, aggiornano, cancellano e consultano i dati SIS attraverso il proprio N.SIS. Gli Stati membri che utilizzano una copia nazionale parziale o completa, o una copia condivisa parziale o completa rendono disponibile tale copia ai fini dell'interrogazione automatizzata nel territorio di ciascuno di tali Stati membri. La copia nazionale o condivisa parziale contiene almeno i dati di cui all'articolo 20, paragrafo 2, lettere da a) a v). Non possono essere consultati gli archivi di dati contenuti nell'N.SIS degli altri Stati membri, salvo in caso di copie condivise.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il CS-SIS svolge funzioni di controllo tecnico e di gestione e dispone di una copia di riserva del CS-SIS in grado di assicurare tutte le funzionalità del CS-SIS principale in caso di guasto. Il CS-SIS e il CS-SIS di riserva sono ubicati nei due siti tecnici dell'eu-LISA.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">L'eu-LISA mette in atto soluzioni tecniche volte a rafforzare la disponibilità ininterrotta del SIS o mediante il funzionamento simultaneo del CS-SIS e il CS-SIS di riserva, purché il CS-SIS di riserva sia in grado di assicurare il funzionamento del SIS in caso di guasto del CS-SIS, o mediante la duplicazione del sistema o delle sue componenti. In deroga ai requisiti procedurali di cui all'articolo 10 del regolamento (UE) 2018/1726 l'eu-LISA elabora, al più tardi il 28 dicembre 2019, uno studio sulle opzioni per le soluzioni tecniche, contenente una valutazione d'impatto indipendente e un'analisi costi-benefici.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">In circostanze eccezionali, l'eu-LISA può, se necessario, creare temporaneamente una copia supplementare della banca dati del SIS.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il CS-SIS fornisce i servizi necessari per l'inserimento e il trattamento dei dati SIS, compresa la consultazione della banca dati del SIS. Per gli Stati membri che usano una copia nazionale o condivisa, il CS-SIS provvede a quanto segue:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">aggiornamento in linea delle copie nazionali;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sincronizzazione e coerenza tra le copie nazionali e la banca dati del SIS; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">funzioni di inizializzazione e ripristino delle copie nazionali.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Il CS-SIS assicura una disponibilità ininterrotta.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Fatti salvi i paragrafi da 1 a 5, i dati SIS possono essere consultati tramite l'ESP.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">Fatti salvi i paragrafi da 1 a 5, i dati SIS possono anche essere trasmessi tramite l'infrastruttura di comunicazione sicura di cui al paragrafo 1, lettera d). La trasmissione è limitata alla misura in cui i dati siano necessari per gli scopi del regolamento (UE) 2019/817.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "5": {"label": "Articolo 5", "heading": "Costi", "anchor": "art_5", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">I costi relativi all'esercizio, alla manutenzione e all'ulteriore sviluppo del SIS centrale e dell'infrastruttura di comunicazione sono a carico del bilancio generale dell'Unione. Tali costi includono il lavoro effettuato con riguardo al CS-SIS per garantire la fornitura dei servizi di cui all'articolo 4, paragrafo 6.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">È assegnato un finanziamento tratto dalla dotazione di 791 milioni di EUR prevista all'articolo 5, paragrafo 5, lettera b), del regolamento (UE) n. 515/2014 per coprire i costi di attuazione del presente regolamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Dalla dotazione di cui al paragrafo 2, e fatti salvi ulteriori finanziamenti a tal fine provenienti da altre fonti del bilancio generale dell'Unione, è assegnato all'eu-LISA un importo di 31 098 000  EUR. Tale finanziamento è attuato mediante gestione indiretta e contribuisce alla realizzazione degli sviluppi tecnici richiesti in virtù del presente regolamento con riguardo al SIS centrale e all'infrastruttura di comunicazione, nonché alle correlate attività di formazione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Dalla dotazione di cui al paragrafo 2 gli Stati membri partecipanti al regolamento (UE) n. 515/2014 ricevono una dotazione globale supplementare pari a 36 810 000  EUR da ripartire in parti uguali tramite una somma forfettaria in aggiunta alla loro dotazione di base. Tale finanziamento è attuato in regime di gestione concorrente ed è destinato interamente all'aggiornamento rapido ed efficace dei sistemi nazionali rilevanti in linea con i requisiti del presente regolamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">I costi per l'istituzione, l'esercizio, la manutenzione e l'ulteriore sviluppo di ciascun N.SIS sono a carico dello Stato membro interessato.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "6": {"label": "Articolo 6", "heading": "Sistemi nazionali", "anchor": "art_6", "frags": [[null, "<p class=\"norm\">Ciascuno Stato membro è competente per l'istituzione, l'esercizio, la manutenzione e l'ulteriore sviluppo del proprio N.SIS e per il collegamento all'NI-SIS.</p>"], [null, "<p class=\"norm\">Ciascuno Stato membro è responsabile di garantire la disponibilità ininterrotta dei dati SIS agli utenti finali.</p>"], [null, "<p class=\"norm\">Ciascuno Stato membro trasmette le proprie segnalazioni tramite il proprio N.SIS.</p>"]]}, "7": {"label": "Articolo 7", "heading": "Ufficio N.SIS e ufficio SIRENE", "anchor": "art_7", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ciascuno Stato membro designa un'autorità («ufficio N.SIS») che ha la competenza centrale per il rispettivo N.SIS.</div>\n</div>"], [null, "<p class=\"norm\">Tale autorità è responsabile del corretto funzionamento e della sicurezza dell'N.SIS, garantisce l'accesso delle autorità competenti al SIS e adotta le misure atte a garantire l'osservanza del presente regolamento. Ha il compito di garantire che tutte le funzionalità del SIS siano messe adeguatamente a disposizione degli utenti finali.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Ciascuno Stato membro designa un'autorità nazionale, operativa 24 ore su 24 e 7 giorni su 7, che garantisca lo scambio e la disponibilità di tutte le informazioni supplementari («ufficio SIRENE») conformemente al manuale SIRENE. Ogni ufficio SIRENE funge da punto di contatto unico per il proprio Stato membro per lo scambio di informazioni supplementari sulle segnalazioni e per agevolare l'adozione delle azioni richieste quando sono inserite nel SIS segnalazioni relative a persone e tali persone sono reperite in seguito a un riscontro positivo (hit).</div>\n</div>"], [null, "<p class=\"norm\">Ogni ufficio SIRENE dispone, in conformità della legislazione nazionale, di un facile accesso diretto o indiretto a tutte le informazioni nazionali pertinenti, comprese le banche dati nazionali e tutte le informazioni sulle segnalazioni degli Stati membri, nonché alla consulenza di esperti per essere in grado di reagire alle richieste di informazioni supplementari in modo rapido ed entro i termini di cui all'articolo 8.</p>"], [null, "<p class=\"norm\">Gli uffici SIRENE coordinano la verifica della qualità delle informazioni inserite nel SIS. A tal fine, essi hanno accesso ai dati trattati nel SIS.</p>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2 <span class=\"italics\">bis</span>.  </span>\n<div class=\"norm inline-element\">Gli uffici SIRENE provvedono alla verifica manuale delle identità diverse a norma dell'articolo 29 del regolamento (UE) 2019/817. Nella misura necessaria ad assolvere tale compito, gli uffici SIRENE hanno accesso ai dati conservati nel CIR e nel MID per le finalità di cui agli articoli 21 e 26 del regolamento (UE) 2019/817.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Gli Stati membri forniscono all'eu-LISA gli estremi dei rispettivi uffici N. SIS e SIRENE. L'eu-LISA pubblica l'elenco degli uffici N. SIS e SIRENE insieme all'elenco di cui all'articolo 41, paragrafo 8.</div>\n</div>"]]}, "8": {"label": "Articolo 8", "heading": "Scambio di informazioni supplementari", "anchor": "art_8", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le informazioni supplementari sono scambiate conformemente alle disposizioni del manuale SIRENE e tramite l'infrastruttura di comunicazione. Gli Stati membri forniscono le risorse tecniche e umane necessarie per garantire in permanenza la disponibilità e lo scambio tempestivo ed efficace delle informazioni supplementari. In caso di indisponibilità dell'infrastruttura di comunicazione, gli Stati membri usano altri mezzi tecnici adeguatamente protetti per lo scambio di informazioni supplementari. Un elenco di mezzi tecnici adeguatamente protetti è riportato nel manuale SIRENE.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le informazioni supplementari sono usate solo per le finalità per le quali sono state trasmesse in conformità dell'articolo 49, a meno che non sia stato ottenuto il previo consenso per un uso ulteriore dallo Stato membro segnalante.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Gli uffici SIRENE svolgono i loro compiti in modo rapido ed efficiente, in particolare rispondendo a una richiesta di informazioni supplementari appena possibile e comunque entro 12 ore dal ricevimento della richiesta.</div>\n</div>"], [null, "<p class=\"norm\">Le richieste di informazioni supplementari da trattare con la massima priorità possono recare la dicitura «URGENT» (urgente) nei formulari SIRENE, seguita dalla specificazione dei motivi dell'urgenza.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La Commissione adotta atti di esecuzione al fine di stabilire norme dettagliate per i compiti degli uffici SIRENE ai sensi del presente regolamento e per lo scambio di informazioni supplementari sotto forma di un manuale intitolato «manuale SIRENE». Tali atti di esecuzione sono adottati secondo la procedura d'esame di cui all'articolo 62, paragrafo 2.</div>\n</div>"]]}, "9": {"label": "Articolo 9", "heading": "Conformità tecnica e funzionale", "anchor": "art_9", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Per consentire una pronta ed efficiente trasmissione dei dati, all'atto dell'istituzione del rispettivo N.SIS ciascuno Stato membro si conforma alle norme, ai protocolli e alle procedure tecniche comuni stabiliti per assicurare la compatibilità del proprio N.SIS con il SIS Centrale.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">In caso di uso di una copia nazionale, lo Stato membro interessato assicura, tramite i servizi forniti dal CS-SIS e gli aggiornamenti automatici di cui all'articolo 4, paragrafo 6, che i dati memorizzati nella copia nazionale siano identici e coerenti con quelli della banca dati del SIS e che un'interrogazione nella copia nazionale produca risultati equivalenti a quelli di un'interrogazione effettuata nella banca dati del SIS.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Gli utenti finali ricevono i dati necessari allo svolgimento dei loro compiti, in particolare, e se necessario, tutti i dati disponibili che consentano di identificare l'interessato e di intraprendere le azioni necessarie.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Gli Stati membri e l'eu-LISA effettuano prove regolari per verificare la conformità tecnica delle copie nazionali di cui al paragrafo 2. I risultati di tali prove sono presi in considerazione nel quadro del meccanismo istituito dal regolamento (UE) n. 1053/2013 del Consiglio (\n<span class=\"superscript\">4</span>\n).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">La Commissione adotta atti di esecuzione al fine di stabilire e sviluppare le norme, i protocolli e le procedure tecniche comuni di cui al paragrafo 1 del presente articolo. Tali atti di esecuzione sono adottati secondo la procedura d'esame di cui all'articolo 62, paragrafo 2.</div>\n</div>"]]}, "10": {"label": "Articolo 10", "heading": "Sicurezza – Stati membri", "anchor": "art_10", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Ciascuno Stato membro, in relazione al proprio N.SIS, adotta le misure necessarie, compresi un piano di sicurezza, un piano di continuità operativa e un piano di ripristino in caso di disastro al fine di:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">proteggere fisicamente i dati, tra l'altro mediante l'elaborazione di piani di emergenza per la protezione delle infrastrutture critiche;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">impedire alle persone non autorizzate l'accesso alle installazioni informatiche utilizzate per il trattamento dei dati personali (controllo all'ingresso delle installazioni);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">impedire che i supporti di dati siano letti, copiati, modificati o rimossi senza autorizzazione (controllo dei supporti di dati);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">impedire che i dati siano inseriti senza autorizzazione e che i dati personali memorizzati siano visionati, modificati o cancellati senza autorizzazione (controllo dell'archiviazione);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">impedire che persone non autorizzate usino sistemi automatizzati di trattamento dei dati mediante apparecchiature per la trasmissione di dati (controllo degli utenti);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">impedire che i dati siano trattati nel SIS senza autorizzazione e che i dati trattati nel SIS siano modificati o cancellati senza autorizzazione (controllo dell'inserimento dei dati);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">garantire che le persone autorizzate a usare un sistema automatizzato di trattamento dei dati possano accedere solo ai dati previsti dalla loro autorizzazione di accesso attraverso identificatori di utente individuali e unici ed esclusivamente con modalità di accesso riservate (controllo dell'accesso ai dati);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">assicurare che tutte le autorità con diritto di accesso al SIS o alle installazioni di trattamento dei dati creino profili che descrivano i compiti e le funzioni delle persone autorizzate ad accedere, inserire, aggiornare, cancellare e consultare i dati e mettano senza indugio tali profili a disposizione delle autorità di controllo di cui all'articolo 55, paragrafo 1, a richiesta di queste (profili del personale);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">garantire la possibilità di verificare e accertare a quali organismi possano essere trasmessi dati personali mediante apparecchiature per la trasmissione di dati (controllo della trasmissione);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>j) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">garantire la possibilità di verificare e accertare a posteriori quali dati personali siano stati introdotti nei sistemi automatizzati di trattamento dei dati, il momento dell'inserimento, la persona che lo ha effettuato e la finalità dello stesso (controllo dell'inserimento);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>k) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">impedire, in particolare mediante tecniche appropriate di cifratura, che all'atto del trasferimento di dati personali nonché del trasporto di supporti di dati essi possano essere letti, copiati, modificati o cancellati senza autorizzazione (controllo del trasporto);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>l) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">monitorare l'efficacia delle misure di sicurezza di cui al presente paragrafo e adottare le necessarie misure organizzative relative al monitoraggio interno per garantire l'osservanza del presente regolamento (autocontrollo);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>m) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">garantire che, in caso di interruzione, i sistemi installati possano essere ripristinati (ripristino); e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>n) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">garantire che il SIS esegua le sue funzioni correttamente, che gli errori siano segnalati (affidabilità) e che i dati personali conservati nel SIS non possano essere falsati da un errore di funzionamento del sistema (integrità).</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli Stati membri adottano misure equivalenti a quelle del paragrafo 1 per quanto riguarda la sicurezza del trattamento e degli scambi di informazioni supplementari, fra l'altro garantendo la sicurezza dei locali degli uffici SIRENE.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Gli Stati membri adottano misure equivalenti a quelle del paragrafo 1 del presente articolo per quanto riguarda la sicurezza del trattamento dei dati SIS da parte delle autorità di cui all'articolo 34.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Le misure descritte nei paragrafi 1, 2 e 3 possono rientrare in un approccio alla sicurezza e in un piano di sicurezza generici a livello nazionale comprendenti molteplici sistemi informatici. In tali casi, i requisiti di cui al presente articolo e la relativa applicabilità al SIS sono chiaramente identificabili in tale piano e garantiti dallo stesso.</div>\n</div>"]]}, "11": {"label": "Articolo 11", "heading": "Riservatezza – Stati membri", "anchor": "art_11", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ogni Stato membro applica le proprie norme in materia di segreto professionale o altri obblighi di riservatezza equivalenti a tutti i soggetti e organismi che debbano lavorare con i dati SIS e con le informazioni supplementari, conformemente alla propria legislazione nazionale. Tale obbligo vincola detti soggetti e organismi anche dopo che hanno rispettivamente lasciato l'incarico o cessato di lavorare, ovvero portato a termine le proprie attività.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Se uno Stato membro collabora con contraenti esterni per un qualsiasi compito relativo al SIS, esso monitora attentamente le attività del contraente per garantire il rispetto di tutte le disposizioni del presente regolamento, in particolare la sicurezza, la riservatezza e la protezione dei dati.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La gestione operativa dell'N.SIS o delle copie tecniche non può essere affidata a imprese o organizzazioni private.</div>\n</div>"]]}, "12": {"label": "Articolo 12", "heading": "Tenuta dei registri a livello nazionale", "anchor": "art_12", "frags": [[null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli Stati membri provvedono affinché ogni accesso ai dati personali e ogni scambio dei medesimi nell'ambito del CS-SIS siano registrati nei rispettivi N.SIS per verificare la legittimità dell'interrogazione, per controllare la liceità del trattamento dei dati, ai fini dell'autocontrollo e per garantire il corretto funzionamento dell'N.SIS, nonché l'integrità e la sicurezza dei dati. Tale requisito non si applica ai processi automatici di cui all'articolo 4, paragrafo 6, lettere a), b) e c).</div>\n</div>"], [null, "<p class=\"norm\">Gli Stati membri provvedono affinché ogni accesso ai dati personali tramite l'ESP sia registrato per verificare la legittimità dell'interrogazione, per controllare la liceità del trattamento dei dati e ai fini dell'autocontrollo e dell'integrità e sicurezza dei dati.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I registri riportano, in particolare, la cronistoria della segnalazione, la data e l'ora dell'attività di trattamento dei dati, i dati usati per effettuare un'interrogazione, un riferimento ai dati trattati e gli identificatori di utente individuali e unici dell'autorità competente e della persona che effettua il trattamento dei dati.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">In deroga al paragrafo 2 del presente articolo, se l'interrogazione è effettuata con dati dattiloscopici o un'immagine del volto in conformità dell'articolo 33, i registri riportano il tipo di dati usati per effettuare l'interrogazione anziché i dati effettivi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">I registri sono utilizzati solo ai fini di cui al paragrafo 1 e sono cancellati tre anni dopo la loro creazione. I registri contenenti la cronistoria delle segnalazioni sono cancellati tre anni dopo la cancellazione delle segnalazioni.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">I registri possono essere tenuti più a lungo dei termini di cui al paragrafo 4 se sono necessari per procedure di controllo già in corso.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Le autorità nazionali competenti incaricate di verificare la legittimità dell'interrogazione, di controllare la liceità del trattamento dei dati, ai fini dell'autocontrollo e per garantire il corretto funzionamento dell'N.SIS e l'integrità e la sicurezza dei dati hanno accesso a tali registri, nei limiti delle rispettive competenze e su loro richiesta, ai fini dell'assolvimento dei loro compiti.</div>\n</div>"]]}, "13": {"label": "Articolo 13", "heading": "Autocontrollo", "anchor": "art_13", "frags": [[null, "<p class=\"norm\">Gli Stati membri provvedono affinché ogni autorità con diritto di accesso ai dati SIS adotti le misure necessarie per conformarsi al presente regolamento e cooperi, se necessario, con l'autorità di controllo.</p>"]]}, "14": {"label": "Articolo 14", "heading": "Formazione del personale", "anchor": "art_14", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Prima di essere autorizzato a trattare dati conservati nel SIS e periodicamente dopo che è stato accordato l'accesso ai dati SIS, il personale delle autorità con diritto di accesso al SIS riceve una formazione adeguata sulla sicurezza dei dati, sui diritti fondamentali, comprese le norme sulla protezione dei dati, nonché sulle procedure di trattamento dei dati previste nel manuale SIRENE. Il personale è informato delle disposizioni relative ai reati e alle sanzioni pertinenti, comprese quelle stabilite all'articolo 59.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli Stati membri dispongono di un programma nazionale di formazione sul SIS che comprende una formazione per gli utenti finali e per il personale degli uffici SIRENE.</div>\n</div>"], [null, "<p class=\"norm\">Tale programma di formazione può rientrare in un programma di formazione generale a livello nazionale comprendente la formazione in altri settori pertinenti.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Almeno una volta l'anno sono organizzati corsi comuni di formazione a livello dell'Unione per rafforzare la cooperazione tra gli uffici SIRENE.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "15": {"label": "Articolo 15", "heading": "Gestione operativa", "anchor": "art_15", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L'eu-LISA è responsabile della gestione operativa del SIS centrale. L'eu-LISA, in collaborazione con gli Stati membri, provvede affinché per il SIS centrale siano utilizzate in ogni momento le migliori tecnologie disponibili, fatta salva un'analisi costi-benefici.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L'eu-LISA è inoltre responsabile dei seguenti compiti relativi all'infrastruttura di comunicazione:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">controllo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sicurezza;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">coordinamento dei rapporti tra gli Stati membri e il gestore.</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">compiti relativi all'esecuzione del bilancio;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">acquisizione e rinnovo; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">aspetti contrattuali.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L'eu-LISA è inoltre responsabile dei seguenti compiti relativi agli uffici SIRENE e alla comunicazione tra gli uffici SIRENE:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">coordinamento, gestione e sostegno delle attività di collaudo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gestione e aggiornamento di specifiche tecniche per lo scambio di informazioni supplementari tra gli uffici SIRENE e l'infrastruttura di comunicazione; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gestione dell'effetto dei cambiamenti tecnici laddove riguardino sia il SIS che lo scambio di informazioni supplementari tra gli uffici SIRENE.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">L'eu-LISA sviluppa e gestisce un meccanismo e procedure per lo svolgimento dei controlli di qualità sui dati contenuti nel CS-SIS. A tale riguardo essa riferisce periodicamente agli Stati membri.</div>\n</div>"], [null, "<p class=\"norm\">L'eu-LISA riferisce periodicamente alla Commissione in merito ai problemi incontrati e agli Stati membri interessati.</p>"], [null, "<p class=\"norm\">La Commissione presenta una relazione periodica al Parlamento europeo e al Consiglio in merito ai problemi di qualità dei dati riscontrati.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">L'eu-LISA svolge anche compiti relativi all'offerta di formazione sull'uso tecnico del SIS e sulle misure atte a migliorare la qualità dei dati SIS.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">La gestione operativa del SIS centrale consiste nell'insieme dei compiti necessari al funzionamento 24 ore su 24 e 7 giorni su 7 del SIS centrale in conformità del presente regolamento, e comprende in particolare le attività di manutenzione e gli adattamenti tecnici necessari per il buon funzionamento del sistema. Tali compiti comprendono anche il coordinamento, la gestione e il sostegno delle attività di collaudo per il SIS centrale e gli N.SIS che garantiscono che il SIS centrale e gli N.SIS operino secondo i requisiti tecnici e funzionali di cui all'articolo 9.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">La Commissione adotta atti di esecuzione al fine di stabilire i requisiti tecnici dell'infrastruttura di comunicazione. Tali atti di esecuzione sono adottati secondo la procedura d'esame di cui all'articolo 62, paragrafo 2.</div>\n</div>"]]}, "16": {"label": "Articolo 16", "heading": "Sicurezza – eu-LISA", "anchor": "art_16", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L'eu-LISA adotta le misure necessarie, compresi un piano di sicurezza, un piano di continuità operativa e un piano di ripristino in caso di disastro per il SIS centrale e l'infrastruttura di comunicazione, al fine di:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">proteggere fisicamente i dati, tra l'altro mediante l'elaborazione di piani di emergenza per la protezione delle infrastrutture critiche;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">impedire alle persone non autorizzate l'accesso alle installazioni informatiche utilizzate per il trattamento dei dati personali (controllo all'ingresso delle installazioni);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">impedire che i supporti di dati siano letti, copiati, modificati o rimossi senza autorizzazione (controllo dei supporti di dati);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">impedire che i dati siano inseriti senza autorizzazione e che i dati personali memorizzati siano visionati, modificati o cancellati senza autorizzazione (controllo dell'archiviazione);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">impedire che persone non autorizzate usino sistemi automatizzati di trattamento dei dati mediante apparecchiature per la trasmissione di dati (controllo degli utenti);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">impedire che i dati siano trattati nel SIS senza autorizzazione e che i dati trattati nel SIS siano modificati o cancellati senza autorizzazione (controllo dell'inserimento dei dati);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">garantire che le persone autorizzate a usare un sistema automatizzato di trattamento dei dati possano accedere solo ai dati previsti dalla loro autorizzazione di accesso attraverso identificatori di utente individuali e unici ed esclusivamente con modalità di accesso riservate (controllo dell'accesso ai dati);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">creare profili che descrivano i compiti e le funzioni delle persone autorizzate ad accedere ai dati o alle installazioni informatiche e mettere senza indugio tali profili a disposizione del Garante europeo della protezione dei dati a richiesta di quest'ultimo (profili del personale);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">garantire la possibilità di verificare e accertare a quali organismi possano essere trasmessi dati personali mediante apparecchiature per la trasmissione di dati (controllo della trasmissione);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>j) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">garantire la possibilità di verificare e accertare a posteriori quali dati personali siano stati introdotti nei sistemi automatizzati di trattamento dei dati, il momento dell'inserimento e la persona che lo ha effettuato (controllo dell'inserimento);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>k) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">impedire, in particolare mediante tecniche appropriate di cifratura, che all'atto del trasferimento di dati personali nonché del trasporto di supporti di dati essi possano essere letti, copiati, modificati o cancellati senza autorizzazione (controllo del trasporto);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>l) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">controllare l'efficacia delle misure di sicurezza di cui al presente paragrafo e adottare le necessarie misure di carattere organizzativo relative al controllo interno per garantire l'osservanza del presente regolamento (autocontrollo);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>m) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">garantire che, in caso di interruzione delle operazioni, i sistemi installati possano essere ripristinati(ripristino);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>n) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">garantire che il SIS esegua le sue funzioni correttamente, che gli errori siano segnalati (affidabilità) e che i dati personali conservati nel SIS non possano essere falsati da un errore di funzionamento del sistema (integrità); e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>o) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">garantire la sicurezza dei suoi siti tecnici.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L'eu-LISA adotta misure equivalenti a quelle del paragrafo 1 per quanto riguarda la sicurezza dell'elaborazione e degli scambi di informazioni supplementari attraverso l'infrastruttura di comunicazione.</div>\n</div>"]]}, "17": {"label": "Articolo 17", "heading": "Riservatezza – eu-LISA", "anchor": "art_17", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Fatto salvo l'articolo 17 dello statuto dei funzionari, l'eu-LISA applica norme adeguate in materia di segreto professionale o altri obblighi di riservatezza equivalenti a tutti i membri del proprio personale che debbano lavorare con i dati SIS, secondo standard equiparabili a quelli previsti dall'articolo 11 del presente regolamento. Tale obbligo vincola gli interessati anche dopo che hanno lasciato l'incarico o cessato di lavorare, ovvero portato a termine le proprie attività.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L'eu-LISA adotta misure equivalenti a quelle di cui al paragrafo 1 per quanto riguarda la riservatezza degli scambi di informazioni supplementari attraverso l'infrastruttura di comunicazione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Se collabora con contraenti esterni per un qualsiasi compito relativo al SIS, l'eu-LISA monitora attentamente le attività del contraente per garantire il rispetto di tutte le disposizioni del presente regolamento, in particolare per quanto concerne la sicurezza, la riservatezza e la protezione dei dati.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La gestione operativa del CS-SIS non può essere affidata a imprese o organizzazioni private.</div>\n</div>"]]}, "18": {"label": "Articolo 18", "heading": "Tenuta dei registri a livello centrale", "anchor": "art_18", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L'eu-LISA provvede affinché ogni accesso a dati personali e ogni scambio dei medesimi nell'ambito del CS-SIS siano registrati ai fini di cui all'articolo 12, paragrafo 1.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I registri riportano, in particolare, la cronistoria della segnalazione, la data e l'ora dell'attività di trattamento dei dati, i dati usati per effettuare un'interrogazione, un riferimento ai dati trattati e gli identificatori di utente individuali e unici dell'autorità competente che effettua il trattamento dei dati.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">In deroga al paragrafo 2 del presente articolo, se l'interrogazione è effettuata con dati dattiloscopici o un'immagine del volto in conformità dell'articolo 33, i registri riportano il tipo di dati usati per effettuare l'interrogazione anziché i dati effettivi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">I registri sono utilizzati solo ai fini di cui al paragrafo 1 e sono cancellati tre anni dopo la loro creazione. I registri contenenti la cronistoria delle segnalazioni sono cancellati tre anni dopo la cancellazione delle segnalazioni.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">I registri possono essere tenuti più a lungo del termine di cui al paragrafo 4 se necessari per procedure di controllo già in corso.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Ai fini dell'autocontrollo e per garantire il corretto funzionamento del CS-SIS nonché l'integrità e la sicurezza dei dati, l'eu-LISA ha accesso a tali registri nei limiti delle sue competenze.</div>\n</div>"], [null, "<p class=\"norm\">Il Garante europeo della protezione dei dati ha accesso a tali registri, nei limiti delle sue competenze e su sua richiesta, ai fini dell'assolvimento dei suoi compiti.</p>"], [null, "<p class=\"modref\">\n▼M2\n</p>"]]}, "18b": {"label": "Articolo 18 ter", "heading": "Tenuta dei registri ai fini dell’interoperabilità con l’ETIAS", "anchor": "art_18b", "frags": [[null, "<p class=\"norm\">Per ciascun trattamento di dati eseguito nel SIS e nell’ETIAS conformemente agli articoli 36 <span class=\"italics\">bis</span> e 36 <span class=\"italics\">ter</span> del presente regolamento è conservato un registro in conformità dell’articolo 18 del presente regolamento e dell’articolo 69 del regolamento (UE) 2018/1240 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">5</span>\n).</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "19": {"label": "Articolo 19", "heading": "Campagne d'informazione sul SIS", "anchor": "art_19", "frags": [[null, "<p class=\"norm\">All'inizio dell'applicazione del presente regolamento, la Commissione, in collaborazione con le autorità di controllo e con il Garante europeo della protezione dei dati, effettua una campagna per informare il pubblico sugli obiettivi del SIS, sui dati ivi conservati, sulle autorità che hanno accesso al SIS e sui diritti degli interessati. La Commissione ripete siffatte campagne a intervalli regolari in collaborazione con le autorità di controllo e con il Garante europeo della protezione dei dati. La Commissione mantiene un sito web a disposizione del pubblico attraverso cui fornire tutte le informazioni pertinenti relative al SIS. Gli Stati membri, in collaborazione con le rispettive autorità di controllo, definiscono e attuano le politiche necessarie per informare i propri cittadini e residenti sul SIS in generale.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "20": {"label": "Articolo 20", "heading": "Categorie di dati", "anchor": "art_20", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Fatti salvi l'articolo 8, paragrafo 1, o le disposizioni del presente regolamento che prevedono la memorizzazione di dati complementari, il SIS contiene esclusivamente le categorie di dati forniti da ciascuno Stato membro che sono necessari ai fini previsti dagli articoli 24 e 25.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le segnalazioni nel SIS che includono informazioni su persone contengono esclusivamente i seguenti dati:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">cognomi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nomi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nomi e cognomi alla nascita;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nomi e cognomi precedenti e alias;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">segni fisici particolari, oggettivi ed inalterabili;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">luogo di nascita;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">data di nascita;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">genere;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ogni cittadinanza posseduta;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>j) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'indicazione che la persona:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è armata;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è violenta;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è fuggita o evasa;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iv) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è a rischio suicidio;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>v) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">pone una minaccia per la salute pubblica; oppure</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>vi) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è coinvolta in un'attività di cui agli articoli da 3 a 14 della direttiva (UE) 2017/541;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>k) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ragione della segnalazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>l) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'autorità autrice della segnalazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>m) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il riferimento alla decisione che ha dato origine alla segnalazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>n) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'azione da intraprendere in caso di riscontro positivo (hit);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>o) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">connessioni con altre segnalazioni a norma dell'articolo 48;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>p) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'indicazione del fatto che la persona interessata è un familiare di un cittadino dell'Unione o di un'altra persona beneficiaria del diritto di libera circolazione a di cui all'articolo 26</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>q) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'indicazione del fatto che la decisione di respingimento e del rifiuto di soggiorno si fonda su uno degli elementi seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">precedente condanna di cui all'articolo 24, paragrafo 2, lettera a);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">grave minaccia per la sicurezza di cui all'articolo 24, paragrafo 2, lettera b);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">elusione della normativa dell'Unione o nazionale che disciplina l'ingresso e il soggiorno di cui all'articolo 24, paragrafo 2, lettera c);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iv) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">divieto d'ingresso di cui all'articolo 24, paragrafo 1, lettera b); oppure</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>v) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">provvedimento restrittivo di cui all'articolo 25;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>r) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">tipo di reato;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>s) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">categoria dei documenti di identificazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>t) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">paese di rilascio dei documenti di identificazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>u) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">numero dei documenti di identificazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>v) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">data di rilascio dei documenti di identificazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>w) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">fotografie e immagini del volto;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>x) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dati dattiloscopici;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>y) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">copia, possibilmente a colori, dei documenti di identificazione.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La Commissione adotta atti di esecuzione al fine di stabilire e sviluppare le norme tecniche necessarie per l'inserimento, l'aggiornamento, la cancellazione e la consultazione dei dati di cui al paragrafo 2 del presente articolo e le norme comuni di cui al paragrafo 4 del presente articolo. Tali atti di esecuzione sono adottati secondo la procedura d'esame di cui all'articolo 62, paragrafo 2.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Le norme tecniche sono simili per le interrogazioni nel CS-SIS, nelle copie nazionali o condivise, e nelle copie tecniche di cui all'articolo 41, paragrafo 2. Tali norme devono essere basate su norme comuni.</div>\n</div>"]]}, "21": {"label": "Articolo 21", "heading": "Proporzionalità", "anchor": "art_21", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Prima di inserire una segnalazione e al momento di prolungare il periodo di validità di una segnalazione, lo Stato membro verifica se l'adeguatezza, la pertinenza e l'importanza del caso giustificano lla segnalazione nel SIS.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Nel caso in cui la decisione di respingimento e di rifiuto di soggiorno di cui all'articolo 24, paragrafo 1, lettera a), è connessa a un reato di terrorismo, il caso è ritenuto adeguato, pertinente e sufficientemente importante da giustificare la segnalazione nel SIS. Per motivi di sicurezza pubblica o nazionale, gli Stati membri possono eccezionalmente astenersi dall'inserire una segnalazione, quando la stessa rischi di ostacolare indagini, inchieste o procedimenti ufficiali o giudiziari.</div>\n</div>"]]}, "22": {"label": "Articolo 22", "heading": "Requisito per inserire una segnalazione", "anchor": "art_22", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L'insieme minimo di dati necessari per inserire una segnalazione nel SIS sono i dati di cui all'articolo 20, paragrafo 2, lettere a), g), k), m), n) e q). Gli altri dati di cui allo stesso paragrafo sono anch'essi inseriti nel SIS, se disponibili.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I dati di cui all'articolo 20, paragrafo 2, lettera e), del presente regolamento sono inseriti solo qualora ciò sia strettamente necessario ai fini dell'identificazione del cittadino di paese terzo interessato. Quando tali dati sono inseriti, gli Stati membri assicurano che l'articolo 9 del regolamento (UE) 2016/679 sia rispettato.</div>\n</div>"]]}, "23": {"label": "Articolo 23", "heading": "Compatibilità delle segnalazioni", "anchor": "art_23", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Prima di inserire una segnalazione, uno Stato membro verifica se la persona interessata sia già stata segnalata nel SIS. A tal fine, è effettuata anche una verifica con i dati dattiloscopici, se tali dati sono disponibili.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Per una stessa persona deve essere inserita nel SIS una sola segnalazione per Stato membro. Se necessario, possono essere inserite nuove segnalazioni sulla stessa persona da altri Stati membri, conformemente al paragrafo 3.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Quando una persona è già stata segnalata nel SIS, uno Stato membro che desideri inserire una nuova segnalazione verifica che non esista alcuna incompatibilità tra le segnalazioni. Se non vi è alcuna incompatibilità, lo Stato membro può inserire la nuova segnalazione. Se le segnalazioni sono incompatibili, gli uffici SIRENE degli Stati membri interessati si consultano tramite lo scambio di informazioni supplementari al fine di raggiungere un accordo. Le norme sulla compatibilità delle segnalazioni sono stabilite nel manuale SIRENE. Per motivi di interesse nazionale essenziale è possibile derogare alle norme sulla compatibilità previa consultazione tra gli Stati membri.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">In caso di riscontri positivi (hit) su segnalazioni multiple di una stessa persona, lo Stato membro di esecuzione si conforma alle norme in materia di priorità delle segnalazioni previste nel manuale SIRENE.</div>\n</div>"], [null, "<p class=\"norm\">Nel caso in cui una persona sia oggetto di segnalazioni multiple inserite da diversi Stati membri, le segnalazioni per l'arresto inserite conformemente all'articolo 26 del regolamento (UE) 2018/1862 sono eseguite in via prioritaria a norma dell'articolo 25 di detto regolamento.</p>"]]}, "24": {"label": "Articolo 24", "heading": "Condizioni per inserire la segnalazione ai fini del respingimento o del rifiuto di soggiorno", "anchor": "art_24", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Gli Stati membri inseriscono una segnalazione ai fini del respingimento e del rifiuto di soggiorno quando è soddisfatta una delle seguenti condizioni:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">lo Stato membro ha concluso, alla luce di una valutazione individuale comprendente anche una valutazione delle circostanze personali del cittadino di paese terzo interessato e delle conseguenze di un respingimento e di un rifiuto di soggiorno, che la presenza di tale cittadino di paese terzo interessato nel proprio territorio costituisce una minaccia per l'ordine pubblico, la sicurezza pubblica o la sicurezza nazionale e, pertanto, ha adottato una decisione giudiziaria o amministrativa in conformità della normativa nazionale ai fini del respingimento e del rifiuto di soggiorno e ha emesso una segnalazione nazionale per gli stessi fini, oppure</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">lo Stato membro ha emesso un divieto d'ingresso secondo procedure conformi alla direttiva 2008/115/CE nei confronti di un cittadino di paese terzo.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le situazioni di cui al paragrafo 1, lettera a), si verificano quando:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il cittadino di paese terzo è stato riconosciuto colpevole in uno Stato membro di un reato che comporta una pena detentiva di almeno un anno;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">esistono fondati motivi per ritenere che il cittadino di paese terzo abbia commesso un reato grave, compreso un reato di terrorismo, o esistono indizi concreti della sua intenzione di commettere un tale reato nel territorio di uno Stato membro; oppure</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il cittadino di paese terzo ha eluso o tentato di eludere la normativa dell'Unione o nazionale che disciplina l'ingresso e il soggiorno nel territorio degli Stati membri.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Lo Stato membro segnalante provvede a che la segnalazione abbia effetto nel SIS non appena il cittadino di paese terzo interessato lascia il territorio degli Stati membri o non appena possibile qualora lo Stato membro segnalante riceva chiare indicazioni del fatto che il cittadino di paese terzo ha lasciato il territorio degli Stati membri al fine di impedire il reingresso di tale cittadino di paese terzo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Le persone nei cui confronti sia stata emessa una decisione di respingimento e di rifiuto di soggiorno, come indicato al paragrafo 1, hanno il diritto di proporre ricorso. Tali ricorsi sono disciplinati conformemente alla normativa dell'Unione o nazionale, i quali forniscono un ricorso effettivo dinanzi a un giudice.</div>\n</div>"]]}, "25": {"label": "Articolo 25", "heading": "Condizioni per l'inserimento della segnalazione di cittadini di paesi terzi oggetto di provvedimenti restrittivi", "anchor": "art_25", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le segnalazioni relative a cittadini di paesi terzi oggetto di un provvedimento restrittivo diretto a impedirne l'ingresso o il transito nel territorio degli Stati membri, disposto in conformità di atti giuridici adottati dal Consiglio, compresi i provvedimenti esecutivi di un divieto di viaggio emanato dal Consiglio di sicurezza delle Nazioni Unite, sono inserite nel SIS, nella misura in cui siano soddisfatte le condizioni relative alla qualità dei dati, ai fini del respingimento e rifiuto di soggiorno.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le segnalazioni sono inserite, aggiornate e cancellate dall'autorità competente dello Stato membro che esercita la presidenza del Consiglio dell'Unione europea al momento dell'adozione della misura. Se detto Stato membro non ha accesso al SIS o alle segnalazioni inserite a norma del presente regolamento, la competenza spetta allo Stato membro che esercita la presidenza successiva e che ha accesso al SIS e alle segnalazioni inserite in conformità del presente regolamento.</div>\n</div>"], [null, "<p class=\"norm\">Gli Stati membri predispongono le procedure necessarie per inserire, aggiornare e cancellare tali segnalazioni.</p>"]]}, "26": {"label": "Articolo 26", "heading": "Condizioni per l'inserimento della segnalazione di cittadini di paesi terzi beneficiari del diritto di libera circolazione nell'Unione", "anchor": "art_26", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La segnalazione di un cittadino di paese terzo beneficiario del diritto di libera circolazione nell'Unione ai sensi della direttiva 2004/38/CE o di un accordo tra l'Unione o l'Unione e i suoi Stati membri, da un lato, e un paese terzo, dall'altro, è conforme alle norme adottate in attuazione di detta direttiva o dell'accordo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">In caso di riscontro positivo (hit) su una segnalazione inserita ai sensi dell'articolo 24 relativa a un cittadino di paese terzo beneficiario del diritto di libera circolazione nell'Unione, lo Stato membro di esecuzione consulta immediatamente lo Stato membro segnalante, tramite scambio di informazioni supplementari, al fine di decidere senza indugio l'azione da intraprendere.</div>\n</div>"]]}, "27": {"label": "Articolo 27", "heading": "Consultazione preventiva prima del rilascio o della proroga di un permesso di soggiorno o di un visto per soggiorno di lunga durata", "anchor": "art_27", "frags": [[null, "<p class=\"norm\">Qualora uno Stato membro esamini la possibilità di rilasciare o di prorogare un permesso di soggiorno o un visto per soggiorno di lunga durata ad un cittadino di paese terzo oggetto di una segnalazione ai fini del respingimento e del rifiuto di soggiorno inserita da un altro Stato membro, gli Stati membri interessati si consultano, tramite lo scambio di informazioni supplementari, in conformità delle disposizioni seguenti:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">lo Stato membro di rilascio consulta lo Stato membro segnalante prima di rilasciare o prorogare il permesso di soggiorno o il visto per soggiorno di lunga durata;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">lo Stato membro segnalante risponde alla richiesta di consultazione entro dieci giorni di calendario;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'assenza di risposta entro il termine di cui alla lettera b) implica che lo Stato membro segnalante non si oppone al rilascio o alla proroga del permesso di soggiorno o del visto per soggiorno di lunga durata;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">al momento di adottare la decisione pertinente, lo Stato membro di rilascio tiene conto dei motivi alla base della decisione dello Stato membro segnalante e prende in considerazione, in conformità della legislazione nazionale, ogni eventuale minaccia per l'ordine pubblico o la sicurezza pubblica che la presenza del cittadino di paese terzo in questione può porre nel territorio degli Stati membri;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">lo Stato membro di rilascio comunica la sua decisione allo Stato membro segnalante; e</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se lo Stato membro di rilascio comunica allo Stato membro segnalante la sua intenzione o la sua decisione di rilasciare o prorogare il permesso di soggiorno o il visto per soggiorno di lunga durata, lo Stato membro segnalante cancella la segnalazione ai fini del respingimento e del rifiuto di soggiorno.</p>\n</div>\n</div>"], [null, "<p class=\"norm\">La decisione finale di rilasciare a un cittadino di paese terzo il permesso di soggiorno o il visto per soggiorno di lunga durata spetta allo Stato membro di rilascio.</p>"]]}, "28": {"label": "Articolo 28", "heading": "Consultazione preliminare prima dell'inserimento di una segnalazione ai fini del respingimento e del rifiuto di soggiorno", "anchor": "art_28", "frags": [[null, "<p class=\"norm\">Qualora uno Stato membro abbia adottato la decisione di cui all'articolo 24, paragrafo 1, ed esamini la possibilità di inserire una segnalazione ai fini del respingimento e del rifiuto di soggiorno per un cittadino di paese terzo che è titolare di un permesso di soggiorno o di un visto per soggiorno di lunga durata validi rilasciati da un altro Stato membro, gli Stati membri interessati si consultano, tramite lo scambio di informazioni supplementari, in conformità delle disposizioni seguenti:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">lo Stato membro che ha adottato la decisione di cui all'articolo 24, paragrafo 1, informa lo Stato membro di rilascio in merito alla decisione;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le informazioni scambiate ai sensi della lettera a) del presente articolo contengono dettagli sufficienti sui motivi alla base della decisione di cui all'articolo 24, paragrafo 1;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sulla base delle informazioni fornite dallo Stato membro che ha adottato la decisione di cui all'articolo 24, paragrafo 1, lo Stato membro di rilascio valuta se vi siano motivi per revocare il permesso di soggiorno o il visto per soggiorno di lunga durata;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">al momento di adottare la decisione pertinente, lo Stato membro di rilascio tiene conto dei motivi alla base della decisione dello Stato membro che ha adottato la decisione di cui all'articolo 24, paragrafo 1, e prende in considerazione, in conformità della legislazione nazionale, ogni eventuale minaccia per l'ordine pubblico o la sicurezza pubblica che la presenza del cittadino di paese terzo in questione può porre nel territorio degli Stati membri;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">entro 14 giorni di calendario dal ricevimento della richiesta di consultazione, lo Stato membro di rilascio comunica la sua decisione allo Stato membro che ha adottato la decisione di cui all'articolo 24, paragrafo 1, o, se non è stato possibile adottare una decisione entro tale termine da parte dello stato di rilascio, gli rivolge una richiesta motivata di prorogare eccezionalmente i termini di risposta per un massimo di altri 12 giorni di calendario;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">qualora lo Stato membro di rilascio comunichi allo Stato membro che ha adottato la decisione di cui all'articolo 24, paragrafo 1, di mantenere il permesso di soggiorno o il visto per soggiorno di lunga durata, lo Stato membro che ha adottato la decisione non inserisce la segnalazione ai fini del respingimento e del rifiuto di soggiorno.</p>\n</div>\n</div>"]]}, "29": {"label": "Articolo 29", "heading": "Consultazione a posteriori dopo l'inserimento di una segnalazione ai fini del respingimento e del rifiuto di soggiorno", "anchor": "art_29", "frags": [[null, "<p class=\"norm\">Qualora risulti che uno Stato membro abbia inserito una segnalazione ai fini del respingimento e del rifiuto di soggiorno per un cittadino di paese terzo che è titolare di un permesso di soggiorno o di un visto per soggiorno di lunga durata validi rilasciati da un altro Stato membro, gli Stati membri interessati si consultano, tramite lo scambio di informazioni supplementari, in conformità delle disposizioni seguenti:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">lo Stato membro segnalante informa lo Stato membro di rilascio in merito alla segnalazione ai fini del respingimento e del rifiuto di soggiorno;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le informazioni scambiate di cui alla lettera a) includono dettagli sufficienti sui motivi alla base della segnalazione ai fini del respingimento e del rifiuto di soggiorno;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">lo Stato membro di rilascio valuta, sulla base delle informazioni fornite dallo Stato membro segnalante, se vi siano motivi per revocare il permesso di soggiorno o il visto per soggiorno di lunga durata;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">al momento di adottare la decisione, lo Stato membro di rilascio tiene conto dei motivi alla base della decisione dello Stato membro segnalante e prende in considerazione, in conformità della legislazione nazionale, ogni eventuale minaccia per l'ordine pubblico o la sicurezza pubblica che la presenza del cittadino di paese terzo in questione può porre nel territorio degli Stati membri;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">entro 14 giorni di calendario dal ricevimento della richiesta di consultazione, lo Stato membro di rilascio comunica allo Stato membro segnalante la sua decisione o, se non è stato possibile per lo Stato membro di rilascio adottare una decisione entro tale termine, gli rivolge una richiesta motivata di proroga dei termini di risposta; i termini possono essere eccezionalmente prorogati per un massimo di altri 12 giorni di calendario;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">qualora lo Stato membro di rilascio comunichi allo Stato membro segnalante di mantenere il permesso di soggiorno o il visto per soggiorno di lunga durata, lo Stato membro segnalante cancella immediatamente la segnalazione ai fini del respingimento e del rifiuto di soggiorno.</p>\n</div>\n</div>"]]}, "30": {"label": "Articolo 30", "heading": "Consultazione in caso di riscontro positivo (hit) riguardante un cittadino di paese terzo titolare di un permesso di soggiorno o di un visto per soggiorno di lunga durata validi", "anchor": "art_30", "frags": [[null, "<p class=\"norm\">Qualora uno Stato membro constati un riscontro positivo (hit) su una segnalazione ai fini del respingimento e del rifiuto di soggiorno inserita da uno Stato membro e riguardante un cittadino di paese terzo che è titolare di un permesso di soggiorno o di un visto per soggiorno di lunga durata validi rilasciati da un altro Stato membro, gli Stati membri interessati si consultano attraverso lo scambio di informazioni supplementari in conformità delle disposizioni seguenti:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">lo Stato membro di esecuzione informa lo Stato membro segnalante in merito alla situazione,</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">lo Stato membro segnalante avvia la procedura di cui all'articolo 29;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">lo Stato membro segnalante comunica allo Stato membro di esecuzione l'esito della consultazione.</p>\n</div>\n</div>"], [null, "<p class=\"norm\">La decisione riguardante l'ingresso del cittadino di paese terzo è adottata dallo Stato membro di esecuzione in conformità del regolamento (UE) 2016/399.</p>"]]}, "31": {"label": "Articolo 31", "heading": "Statistiche", "anchor": "art_31", "frags": [[null, "<p class=\"norm\">Ogni anno gli Stati membri forniscono all'eu-LISA statistiche annuali sugli scambi di informazioni effettuati ai sensi degli articoli da 27 a 30 e sui casi in cui i termini non sono stati rispettati.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "32": {"label": "Articolo 32", "heading": "Norme specifiche per inserire fotografie, immagini del volto e dati dattiloscopici", "anchor": "art_32", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Sono inseriti nel SIS unicamente le fotografie, le immagini del volto e i dati dattiloscopici di cui all'articolo 20, paragrafo 2, lettere w) e x) che soddisfano norme minime di qualità dei dati e specifiche tecniche. Tali dati sono inseriti solo previo controllo di qualità volto ad accertare che siano state soddisfatte le norme minime di qualità dei dati e le specifiche tecniche.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I dati dattiloscopici inseriti nel SIS possono essere costituiti da una a dieci impronte digitali piane e da una a dieci impronte digitali rollate. Possono inoltre includere due impronte palmari.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Per l'archiviazione dei dati biometrici di cui al paragrafo 1 del presente articolo sono stabilite norme minime di qualità e specifiche tecniche in conformità del paragrafo 4 del presente articolo. Tali norme minime di qualità e specifiche tecniche stabiliscono il livello di qualità richiesto per l'uso dei dati ai fini della verifica dell'identità della persona in conformità dell'articolo 33, paragrafo 1, e per l'uso dei dati ai fini dell'identificazione della persona in conformità dell'articolo 33, paragrafi da 2 a 4.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La Commissione adotta atti di esecuzione al fine di stabilire le norme minime di qualità dei dati e le specifiche tecniche di cui ai paragrafi 1 e 3 del presente articolo. Tali atti di esecuzione sono adottati secondo la procedura d'esame di cui all'articolo 62, paragrafo 2.</div>\n</div>"]]}, "33": {"label": "Articolo 33", "heading": "Norme specifiche per la verifica o l'interrogazione tramite fotografie, immagini del volto e dati dattiloscopici", "anchor": "art_33", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Qualora siano disponibili fotografie, immagini del volto e dati dattiloscopici in una segnalazione nel SIS, tali fotografie, immagini del volto e dati dattiloscopici sono usati per confermare l'identità di una persona reperita grazie all'interrogazione del SIS con dati alfanumerici.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I dati dattiloscopici possono essere consultati in tutti i casi per identificare una persona. Tuttavia i dati dattiloscopici sono consultati a fini di identificazione di una persona se l'identità della persona non può essere accertata con altri mezzi. A tal fine il SIS centrale contiene un sistema automatico per il riconoscimento delle impronte digitali (AFIS).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">I dati dattiloscopici nel SIS in relazione a segnalazioni inserite a norma degli articoli 24 e 25 possono essere consultati anche usando serie complete o incomplete di impronte digitali o palmari rinvenute sul luogo di un reato grave o di un reato di terrorismo oggetto di indagine qualora si possa stabilire con un elevato grado di probabilità che tali serie di impronte appartengono a un autore del reato e purché l'interrogazione sia effettuata simultaneamente nelle pertinenti banche dati nazionali di impronte digitali dello Stato membro.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Non appena divenga tecnicamente possibile, e garantendo al contempo un grado elevato di affidabilità dell'identificazione, è possibile ricorrere a fotografie e immagini del volto per identificare una persona presso valichi di frontiera regolari.</div>\n</div>"], [null, "<p class=\"norm\">Prima che questa funzionalità sia attuata nel SIS, la Commissione presenta una relazione sulla disponibilità, sullo stato di preparazione e sull'affidabilità della tecnologia necessaria. Il Parlamento europeo è consultato in merito alla relazione.</p>"], [null, "<p class=\"norm\">Dopo l'inizio dell'uso della funzionalità ai valichi di frontiera regolari, alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 61 per integrare il presente regolamento riguardo alla determinazione degli altri casi in cui è possibile ricorrere a fotografie e immagini del volto per identificare le persone.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "34": {"label": "Articolo 34", "heading": "Autorità competenti nazionali con diritto di accesso ai dati in SIS", "anchor": "art_34", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le autorità nazionali competenti responsabili dell'accertamento dell'identità dei cittadini di paesi terzi hanno accesso ai dati inseriti nel SIS e il diritto di consultarli direttamente o su una copia di dati SIS ai fini:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dei controlli di frontiera, a norma del regolamento (UE) 2016/399;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dei controlli di polizia e doganali effettuati all'interno dello Stato membro interessato e del relativo coordinamento da parte delle autorità designate;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">della prevenzione, dell'accertamento, dell'indagine o del perseguimento di reati di terrorismo o di altri reati gravi o dell'esecuzione di sanzioni penali, nello Stato membro interessato, purché si applichi la direttiva (UE) 2016/680;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dell'esame delle condizioni e dell'adozione di decisioni in materia di ingresso e soggiorno di cittadini di paesi terzi sul territorio degli Stati membri, compreso sui permessi di soggiorno e sui visti per soggiorni di lunga durata, e in materia di rimpatrio di cittadini di paesi terzi, nonché delle verifiche sui cittadini di paesi terzi che entrano o soggiornano illegalmente nel territorio degli Stati membri;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dei controlli di sicurezza sui cittadini di paesi terzi che chiedono la protezione internazionale, nella misura in cui le autorità che svolgono i controlli non siano «autorità accertanti» ai sensi dell'articolo 2, lettera f), della direttiva 2013/32/UE del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">6</span>\n) e, se del caso, della consulenza fornita in conformità del regolamento (CE) n. 377/2004 del Consiglio (\n<span class=\"superscript\">7</span>\n);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dell'esame delle domande di visto e dell'assunzione delle relative decisioni, comprese le decisioni di annullamento, revoca o proroga del visto in conformità del regolamento (CE) n. 810/2009 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">8</span>\n);</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M1\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">della verifica delle identità diverse e del contrasto della frode di identità in conformità del capo V del regolamento (UE) 2019/817;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M2\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">del trattamento manuale delle domande ETIAS da parte dell’unità nazionale ETIAS a norma dell’articolo 8 del regolamento (UE) 2018/1240.</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il diritto di accesso ai dati nel SIS e il diritto di consultarli direttamente possono essere esercitati dalle autorità nazionali competenti che sono responsabili della naturalizzazione, come previsto nella legislazione nazionale, ai fini dell'esame della domanda di naturalizzazione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Ai fini degli articoli 24 e 25, il diritto di accesso ai dati presenti nel SIS e il diritto di consultarli direttamente possono essere esercitati anche dalle autorità giudiziarie nazionali, comprese quelle competenti per l'avvio dell'azione penale e per le indagini giudiziarie prima dell'imputazione, nell'assolvimento delle loro funzioni, come previsto nel diritto nazionale, e dalle relative autorità di coordinamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Il diritto di accesso ai dati riguardanti documenti su persone inseriti a norma dell'articolo 38, paragrafo 2, lettere k) e l), del regolamento (UE) 2018/1862 e il diritto di consultarli possono essere esercitati anche dalle autorità di cui al paragrafo 1, lettera f) del presente articolo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Le autorità competenti di cui al presente articolo sono inserite nell'elenco di cui all'articolo 41, paragrafo 8.</div>\n</div>"]]}, "35": {"label": "Articolo 35", "heading": "Accesso di Europol ai dati nel SIS", "anchor": "art_35", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L'Agenzia dell'Unione europea per la cooperazione nell'attività di contrasto (Europol), istituita dal regolamento (UE) 2016/794, ove necessario all'adempimento del suo mandato, ha il diritto di accedere ai dati nel SIS e di consultarli. Europol può anche scambiare e richiedere ulteriori informazioni supplementari in conformità delle disposizioni del manuale SIRENE.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Qualora un'interrogazione effettuata da Europol riveli la presenza di una segnalazione nel SIS, Europol ne informa lo Stato membro segnalante tramite lo scambio di informazioni supplementari a mezzo dell'infrastruttura di comunicazione e conformemente alle disposizioni del manuale SIRENE. Finché non è in grado di utilizzare le funzionalità previste per lo scambio di informazioni supplementari, Europol informa lo Stato membro segnalante tramite i canali definiti dal regolamento (UE) 2016/794.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Europol può trattare le informazioni supplementari fornitele dagli Stati membri a fini di raffronto con le proprie banche dati e i progetti di analisi operativa, allo scopo di identificare collegamenti o altri nessi pertinenti e per analisi strategiche, tematiche od operative di cui all'articolo 18, paragrafo 2, lettere a), b) e c), del regolamento (UE) 2016/794. Qualsiasi trattamento di informazioni supplementari da parte di Europol ai fini del presente articolo è effettuato in conformità di tale regolamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">L'uso da parte di Europol delle informazioni ottenute tramite un'interrogazione del SIS o tramite il trattamento di informazioni supplementari è soggetto al consenso dello Stato membro segnalante. Se lo Stato membro acconsente all'uso di tali informazioni, il loro trattamento da parte di Europol è disciplinato dal regolamento (UE) 2016/794. Le informazioni sono trasmesse da Europol a paesi terzi e organismi terzi solamente con il consenso dello Stato membro segnalante e in modo pienamente conforme alla normativa dell'Unione in materia di protezione dei dati.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Europol:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">fatti salvi i paragrafi 4 e 6, non collega parti del SIS, né trasferisce i dati in esso contenuti cui ha accesso, a sistemi di raccolta e trattamento di dati gestiti da o presso Europol e non scarica o copia altrimenti parti del SIS;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">in deroga all'articolo 31, paragrafo 1, del regolamento (UE) 2016/794, cancella le informazioni supplementari contenenti dati personali entro un anno dalla cancellazione della relativa segnalazione. A titolo di deroga, se Europol dispone di informazioni nelle proprie banche dati o nei progetti di analisi operativa su un caso cui si riferiscono le informazioni supplementari, Europol può, in via eccezionale, continuare a conservare le informazioni supplementari per svolgere i suoi compiti, ove necessario. Europol informa lo Stato membro segnalante e quello di esecuzione dell'ulteriore conservazione di tali informazioni supplementari e ne fornisce una giustificazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">limita l'accesso ai dati nel SIS, comprese le informazioni supplementari, al proprio personale specificamente autorizzato che necessita dell'accesso a tali dati per l'assolvimento dei propri compiti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">adotta e applica misure per garantire la sicurezza, la riservatezza e l'autocontrollo a norma degli articoli 10, 11 e 13;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">provvede affinché il proprio personale autorizzato a trattare i dati del SIS riceva una formazione e informazioni adeguate a norma dell'articolo 14, paragrafo 1; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">fatto salvo il regolamento (UE) 2016/794, consente al Garante europeo della protezione dei dati di sorvegliare ed esaminare le attività da essa svolte nell'esercizio del suo diritto di accesso ai dati nel SIS e di consultazione degli stessi e nello scambio e nel trattamento di informazioni supplementari.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Europol duplica i dati dal SIS soltanto per fini tecnici ove tale duplicazione sia necessaria per la consultazione diretta da parte del personale debitamente autorizzato di Europol. Il presente regolamento si applica a tali copie. La copia tecnica è usata solamente al fine di conservare i dati SIS mentre tali dati sono consultati. Una volta consultati i dati, la copia è cancellata. Tali usi non sono considerati scaricamento o duplicazione illeciti di dati SIS. Europol non copia i dati di una segnalazione né i dati complementari trasmessi dagli Stati membri o dal CS-SIS negli altri sistemi di Europol.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Per verificare la liceità del trattamento dei dati, per l'autocontrollo e per garantire un'adeguata sicurezza e integrità dei dati, Europol conserva registri di tutti gli accessi al SIS e le interrogazioni del SIS in conformità dell'articolo 12. Tali registri e tale documentazione non sono considerati scaricamenti o duplicazioni illeciti di parti del SIS.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Gli Stati membri informano Europol, tramite lo scambio di informazioni supplementari, in merito a qualsiasi riscontro positivo (hit) su segnalazioni relative a reati di terrorismo. Gli Stati membri possono eccezionalmente astenersi dall'informare Europol, se ciò comprometterebbe le indagini in corso, la sicurezza di una persona, o sarebbe in contrasto con gli interessi essenziali della sicurezza dello Stato membro segnalante.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">Il paragrafo 8 si applica a decorrere dalla data in cui Europol è in grado di ricevere informazioni supplementari in conformità del paragrafo 1.</div>\n</div>"]]}, "36": {"label": "Articolo 36", "heading": "Accesso ai dati nel SIS da parte delle squadre della guardia di frontiera e costiera europea, di squadre di personale che assolve compiti attinenti al rimpatrio e dei membri delle squadre di sostegno per la gestione della migrazione", "anchor": "art_36", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">A norma dell'articolo 40, paragrafo 8, del regolamento (UE) 2016/1624, i membri delle squadre ai sensi dell'articolo 2, punti 8) e 9), di tale regolamento hanno, nell'ambito dei rispettivi mandati e a condizione che siano autorizzati a effettuare controlli a norma dell'articolo 34, paragrafo 1, del presente regolamento e abbiano ricevuto la formazione necessaria a norma dell'articolo 14, paragrafo 1, del presente regolamento il diritto di accedere ai dati inseriti nel SIS e di consultarli, nella misura in cui ciò sia necessario per l'assolvimento dei loro compiti e sia richiesto dal piano operativo per un'operazione specifica. L'accesso ai dati nel SIS non è esteso ad altri membri delle squadre.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I membri delle squadre di cui al paragrafo 1 esercitano il diritto di accedere ai dati nel SIS e di consultarli in conformità del paragrafo 1 tramite un'interfaccia tecnica. L'interfaccia tecnica è istituita e gestita dall'Agenzia europea della guardia di frontiera e costiera e permette un collegamento diretto con il SIS centrale.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Qualora un'interrogazione effettuata da un membro delle squadre di cui al paragrafo 1 del presente articolo riveli l'esistenza di una segnalazione nel SIS, lo Stato membro segnalante ne è informato. In conformità dell'articolo 40 del regolamento (UE) 2016/1624, i membri delle squadre intervengono esclusivamente in risposta a una segnalazione nel SIS sotto il controllo e, di norma, in presenza di guardie di frontiera o di personale che assolve compiti attinenti al rimpatrio dello Stato membro ospitante in cui operano. Lo Stato membro ospitante può autorizzare i membri delle squadre ad agire per suo conto.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Per verificare la liceità del trattamento dei dati, per l'autocontrollo e per garantire un'adeguata sicurezza e integrità dei dati, l'Agenzia europea della guardia di frontiera e costiera conserva registri di tutti gli accessi al SIS e le interrogazioni del SIS in conformità dell'articolo 12.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">L'Agenzia europea della guardia di frontiera e costiera adotta e applica misure per garantire la sicurezza, la riservatezza e l'autocontrollo a norma degli articoli 10, 11 e 13 e provvede affinché le squadre di cui al paragrafo 1 del presente articolo applichino tali misure.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Nulla nel presente articolo può essere interpretato nel senso di pregiudicare le disposizioni del regolamento (UE) 2016/1624 concernenti la protezione dei dati né la responsabilità dell'Agenzia europea della guardia di frontiera e costiera per trattamenti non autorizzati o scorretti deidati.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Fatto salvo il paragrafo 2, nessuna parte del SIS è collegata a un sistema di raccolta e trattamento di dati gestito dalle squadre di cui al paragrafo 1 o dall'Agenzia europea della guardia di frontiera e costiera, e nessun dato nel SIS a cui hanno accesso tali squadre è trasferito a tale sistema. Nessuna parte del SIS può essere scaricata o duplicata. La registrazione degli accessi e delle interrogazioni non è considerata scaricamento illegale o duplicazione di dati SIS.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">L'Agenzia europea della guardia di frontiera e costiera consente al Garante europeo della protezione dei dati di sorvegliare ed esaminare le attività svolte dalle squadre di cui al presente articolo nell'esercizio del loro diritto di accesso ai dati nel SIS e di consultazione degli stessi. Ciò non pregiudica le ulteriori disposizioni del regolamento (UE) 2018/1725.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M2\n</p>"]]}, "36b": {"label": "Articolo 36 ter", "heading": "Accesso ai dati SIS da parte dell’unità centrale ETIAS", "anchor": "art_36b", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ai fini dell’esercizio dei compiti conferitile dal regolamento (UE) 2018/1240, l’unità centrale ETIAS, istituita nell’ambito dell’Agenzia europea della guardia di frontiera e costiera a norma dell’articolo 7 di detto regolamento, ha il diritto di accedere e di consultare i dati SIS pertinenti conformemente all’articolo 11, paragrafo 8, del medesimo regolamento. All’accesso e alla consultazione si applica l’articolo 36, paragrafi da 4 a 8, del presente regolamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Fatto salvo l’articolo 24 del regolamento (UE) 2018/1240, qualora la verifica dell’unità centrale ETIAS in conformità dell’articolo 22 di tale regolamento confermi una corrispondenza tra i dati registrati nel fascicolo di domanda ETIAS e quelli di una segnalazione nel SIS, o qualora a seguito di tale verifica persistano dubbi, si applica la procedura di cui all’articolo 26 di tale regolamento.</div>\n</div>"]]}, "36c": {"label": "Articolo 36 quater", "heading": "Interoperabilità con l’ETIAS", "anchor": "art_36c", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">A partire dalla data di entrata in funzione dell’ETIAS, come determinata in conformità dell’articolo 88, paragrafo 1, del regolamento (UE) 2018/1240, il SIS centrale è connesso all’ESP per consentire le verifiche di cui all’articolo 20, all’articolo 23, all’articolo 24, paragrafo 6, lettera c), punto ii), all’articolo 41 e all’articolo 54, paragrafo 1, lettera b), di tale regolamento e le successive verifiche di cui agli articoli 22 e 26 del medesimo articolo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Ai fini delle verifiche di cui all’articolo 20, paragrafo 2, lettera c) e lettera m), punto ii), e lettera o) del regolamento (UE) 2018/1240, il sistema centrale ETIAS usa l’ESP per confrontare i dati di cui all’articolo 11, paragrafo 4, del medesimo regolamento con quelli contenuti nel SIS, conformemente all’articolo 11, paragrafo 8, di detto regolamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Ai fini delle verifiche di cui all’articolo 24, paragrafo 6, lettera c), punto ii), e all’articolo 54, paragrafo 1, lettera b), del regolamento (UE) 2018/1240, il sistema centrale ETIAS usa l’ESP per verificare regolarmente se è stata cancellata una segnalazione ai fini del rifiuto d’ingresso e di soggiorno inserita nel SIS, che abbia dato luogo al rifiuto, all’annullamento o alla revoca di un’autorizzazione ai viaggi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Ai sensi dell’articolo 41, paragrafo 3, del regolamento (UE) 2018/1240, qualora sia inserita nel SIS una nuova segnalazione ai fini del rifiuto d’ingresso e di soggiorno, il SIS centrale trasmette i dati cui all’articolo 20, paragrafo 2, lettere da a) a d), da f) a i) e da s) a v) del presente regolamento al sistema centrale ETIAS utilizzando l’ESP, ai fini della verifica dell’eventuale corrispondenza della nuova segnalazione a un’autorizzazione ai viaggi valida.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "37": {"label": "Articolo 37", "heading": "Valutazione dell'uso del SIS da parte di Europol e dell'Agenzia europea della guardia di frontiera e costiera", "anchor": "art_37", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La Commissione effettua almeno ogni cinque anni una valutazione dell'esercizio e dell'uso del SIS da parte di Europol e delle squadre di cui all'articolo 36, paragrafo 1.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Europol e l'Agenzia europea della guardia di frontiera e costiera garantiscono un seguito adeguato alle conclusioni e alle raccomandazioni risultanti da tale valutazione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Una relazione sui risultati della valutazione e sul relativo seguito è trasmessa al Parlamento europeo e al Consiglio.</div>\n</div>"]]}, "38": {"label": "Articolo 38", "heading": "Ambito dell'accesso", "anchor": "art_38", "frags": [[null, "<p class=\"norm\">Gli utenti finali, compresi Europol e i membri delle squadre ai sensi dell'articolo 2, punti 8) e 9), del regolamento (UE) 2016/1624, accedono solo ai dati necessari per l'assolvimento dei loro compiti.</p>"]]}, "39": {"label": "Articolo 39", "heading": "Periodo di riesame delle segnalazioni", "anchor": "art_39", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le segnalazioni sono conservate esclusivamente per il periodo necessario a realizzare le finalità per le quali sono state inserite.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Lo Stato membro segnalante riesamina la necessità di conservare una segnalazione entro tre anni dal suo inserimento nel SIS. Tuttavia se la decisione nazionale su cui si basa la segnalazione prevede un periodo di validità superiore a tre anni, la segnalazione è riesaminata entro cinque anni.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Ciascuno Stato membro fissa, se del caso, tempi di riesame più brevi conformemente alla legislazione nazionale.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Nel periodo di riesame lo Stato membro segnalante può decidere, a seguito di una valutazione individuale globale che è registrata, di mantenere la segnalazione per un periodo più lungo del periodo di riesame, ove ciò sia necessario e proporzionato alle finalità per le quali la segnalazione stessa era stata inserita. In tal caso il paragrafo 2 si applica anche a tale proroga. Ogni proroga è comunicata al CS-SIS.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Le segnalazioni sono cancellate automaticamente allo scadere del periodo di riesame di cui al paragrafo 2, salvo qualora lo Stato membro segnalante abbia informato il CS-SIS della proroga a norma del paragrafo 4. Il CS-SIS segnala automaticamente agli Stati membri, con quattro mesi d'anticipo, la prevista cancellazione di dati dal sistema.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Gli Stati membri redigono statistiche sul numero di segnalazioni il cui periodo di conservazione è stato prorogato a norma del paragrafo 4 del presente articolo e le trasmettono, su richiesta, alle autorità di controllo di cui all'articolo 55.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Non appena risulti chiaro all' ufficio SIRENE che una segnalazione ha conseguito il suo obiettivo e deve pertanto essere cancellata, l'ufficio SIRENE ne informa immediatamente l'autorità autrice della segnalazione. L'autorità dispone di 15 giorni di calendario dal ricevimento di tale comunicazione per rispondere che la segnalazione è stata o sarà cancellata, oppure indica i motivi della conservazione della segnalazione. In caso di mancata ricezione di una risposta alla scadenza del periodo di 15 giorni, l'ufficio SIRENE provvede affinché la segnalazione sia cancellata. Laddove consentito dalla legislazione nazionale, la segnalazione è cancellata dall'ufficio SIRENE. Gli uffici SIRENE segnalano alla rispettiva autorità di controllo i problemi ricorrenti incontrati nell'attività svolta ai sensi del presente paragrafo.</div>\n</div>"]]}, "40": {"label": "Articolo 40", "heading": "Cancellazione delle segnalazioni", "anchor": "art_40", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La segnalazione riguardante il respingimento e rifiuto di soggiorno ai sensi dell'articolo 24 è cancellata:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">allorché la decisione su cui si basava è stata revocata o annullata dall'autorità competente, oppure</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ove applicabile, in esito alla procedura di consultazione prevista dall'articolo 27 e dall'articolo 29.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La segnalazione di un cittadino di paese terzo oggetto di un provvedimento restrittivo diretto a impedirne l'ingresso o il transito nel territorio degli Stati membri è cancellata quando prende fine, è sospeso o è annullato il provvedimento restrittivo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La segnalazione relativa alla persona che acquista la cittadinanza di uno Stato membro o di uno Stato i cui cittadini beneficiano del diritto di libera circolazione in virtù del diritto dell'Unione è cancellata non appena lo Stato membro segnalante viene a conoscenza o viene informato a norma dell'articolo 44 di tale acquisto.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Le segnalazioni sono cancellate alla loro scadenza ai sensi dell'articolo 39.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "41": {"label": "Articolo 41", "heading": "Trattamento dei dati del SIS", "anchor": "art_41", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli Stati membri possono solo trattare i dati di cui all'articolo 20 ai fini del respingimento e del rifiuto di soggiorno nel loro territorio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I dati sono duplicati soltanto per fini tecnici, sempreché tale duplicazione sia necessaria per la consultazione diretta da parte delle autorità competenti di cui all'articolo 34. Il presente regolamento si applicano a tali copie. Gli Stati membri non copiano i dati della segnalazione o i dati complementari inseriti da un altro Stato membro nel proprio N.SIS o nel CS-SIS.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Le copie tecniche di cui al paragrafo 2 che portano alla creazione di banche dati off-line possono essere conservate per un periodo non superiore a 48 ore.</div>\n</div>"], [null, "<p class=\"norm\">Nonostante il disposto del primo comma, non sono permesse copie tecniche che portino alla creazione di banche dati off-line ad uso delle autorità preposte al rilascio dei visti, fatta eccezione per le copie destinate ad essere usate esclusivamente in caso di emergenza in seguito all'indisponibilità della rete per oltre 24 ore.</p>"], [null, "<p class=\"norm\">Gli Stati membri tengono un inventario aggiornato di tali copie, lo rendono accessibile alle rispettive autorità di controllo e assicurano che il presente regolamento, in particolare l'articolo 10, sia applicato a tali copie.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">L'accesso ai dati del SIS da parte delle autorità competenti nazionali di cui all'articolo 34 è autorizzato esclusivamente nei limiti delle loro competenze e riservato solamente al personale debitamente autorizzato.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Ogni trattamento delle informazioni del SIS dagli Stati membri per finalità diverse da quelle per le quali vi sono state inserite deve essere connesso a un caso specifico e giustificato dalla necessità di prevenire una minaccia grave e imminente per l'ordine pubblico e la sicurezza pubblica, da fondati motivi di sicurezza nazionale o ai fini della prevenzione di un reato grave. A tale scopo è necessario ottenere l'autorizzazione preventiva dello Stato membro segnalante.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">I dati riguardanti documenti su persone inseriti nel SIS a norma dell'articolo 38, paragrafo 2, lettere k) e l), del regolamento (UE) 2018/1862 possono essere usati dalle autorità competenti di cui all'articolo 34, paragrafo 1, lettera f), conformemente alla legislazione di ciascuno Stato membro.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Qualsiasi uso dei dati del SIS non conforme ai paragrafi da 1 a 6 del presente articolo è considerato un abuso ai sensi della legislazione di ciascuno Stato membro ed è soggetto a sanzioni in conformità dell'articolo 59.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Ciascuno Stato membro invia all'eu-LISA l'elenco delle proprie autorità competenti autorizzate a consultare direttamente i dati nel SIS a norma del presente regolamento e le eventuali modifiche apportate all'elenco. L'elenco indica, per ciascuna autorità, i dati che essa può consultare e per quali finalità. L'eu-LISA provvede affinché l'elenco sia pubblicato nella <span class=\"italics\">Gazzetta ufficiale dell'Unione europea</span> annualmente. L'eu-LISA mantiene sul proprio sito web un elenco sempre aggiornato contenente le modifiche trasmesse dagli Stati membri tra una pubblicazione annuale e l'altra.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">Nella misura in cui il diritto dell'Unione non preveda specifiche disposizioni, la legislazione di ciascuno Stato membro si applica ai dati nel rispettivo N.SIS.</div>\n</div>"]]}, "42": {"label": "Articolo 42", "heading": "Dati SIS e archivi nazionali", "anchor": "art_42", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L'articolo 41, paragrafo 2, non pregiudica il diritto di uno Stato membro di conservare nel proprio archivio nazionale i dati SIS in collegamento con i quali è stata svolta un'azione nel suo territorio. Tali dati sono conservati negli archivi nazionali per un periodo massimo di tre anni, a meno che disposizioni specifiche di diritto nazionale prevedano un periodo di conservazione più lungo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L'articolo 41, paragrafo 2, non pregiudica il diritto di uno Stato membro di conservare nel proprio archivio nazionale i dati contenuti in una segnalazione particolare inserita nel SIS da quello stesso Stato membro.</div>\n</div>"]]}, "43": {"label": "Articolo 43", "heading": "Informazione in caso di mancata esecuzione di una segnalazione", "anchor": "art_43", "frags": [[null, "<p class=\"norm\">Se l'azione richiesta non può essere eseguita, lo Stato membro che ha richiesto l'intervento ne informa senza indugio lo Stato membro segnalante tramite lo scambio di informazioni supplementari.</p>"]]}, "44": {"label": "Articolo 44", "heading": "Qualità dei dati trattati nel SIS", "anchor": "art_44", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Lo Stato membro segnalante è responsabile dell'esattezza e dell'attualità dei dati e della liceità del loro inserimento e della loro conservazione nel SIS.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Qualora uno Stato membro segnalante riceva pertinenti dati complementari o modificati di cui all'articolo 20, paragrafo 2, esso completa o modifica senza indugio la segnalazione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Solo lo Stato membro segnalante è autorizzato a modificare, completare, rettificare, aggiornare o cancellare i dati che ha inserito nel SIS.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Qualora uno Stato membro diverso dallo Stato membro segnalante disponga di pertinenti dati complementari o modificati di cui all'articolo 20, paragrafo 2, esso li trasmette senza indugio, tramite lo scambio di informazioni supplementari, allo Stato membro segnalante per consentirgli di completare o modificare la segnalazione. I dati sono trasmessi solo se l'identità del cittadino di paese terzo è accertata.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Se uno Stato membro diverso dallo Stato membro segnalante è in possesso di elementi che dimostrano che detti dati contengono errori di fatto o sono stati archiviati illecitamente, ne informa al più presto, tramite lo scambio di informazioni supplementari ed entro due giorni lavorativi dacché è in possesso di detti elementi, lo Stato membro segnalante. Lo Stato membro segnalante verifica l'informazione e, se necessario, rettifica o cancella senza indugio i dati in questione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Se, entro due mesi dal momento in cui sono emersi gli elementi ai sensi del paragrafo 5 del presente articolo gli Stati membri non giungono a un accordo, lo Stato membro che non ha inserito la segnalazione sottopone la questione alle autorità di controllo interessate e al Garante europeo della protezione dei dati affinché prendano una decisione mediante la cooperazione in conformità dell'articolo 57.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Gli Stati membri si scambiano informazioni supplementari nei casi in cui una persona presenti un ricorso nel quale faccia valere di non essere la persona oggetto della segnalazione. Se dalla verifica risulta che la persona oggetto della segnalazione è una persona distinta dal ricorrente, il ricorrente è informato delle disposizioni dell'articolo 47 e del suo diritto di ricorso di cui all'articolo 54, paragrafo 1.</div>\n</div>"]]}, "45": {"label": "Articolo 45", "heading": "Incidenti di sicurezza", "anchor": "art_45", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">È considerato incidente di sicurezza qualunque evento che ha o possa avere ripercussioni sulla sicurezza del SIS o possa causare danni o perdite ai dati SIS o alle informazioni supplementari, in particolare quando possano essere stati consultati dati illecitamente o quando sono state o possano essere state compromesse la disponibilità, l'integrità e la riservatezza dei dati.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli incidenti di sicurezza sono gestiti in modo tale da garantire una risposta rapida, efficace e adeguata.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Fatte salve la notifica e la comunicazione di una violazione dei dati personali a norma dell'articolo 33 del regolamento (UE) 2016/679 o dell'articolo 30 della direttiva (UE) 2016/680, gli Stati membri, Europol e l'Agenzia europea della guardia di frontiera e costiera comunicano senza indugio gli incidenti di sicurezza alla Commissione, all'eu-LISA, all'autorità di controllo competente e al Garante europeo della protezione dei dati. L'eu-LISA comunica senza indugio qualsiasi incidente di sicurezza relativo al SIS centrale alla Commissione e al Garante europeo della protezione dei dati.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Le informazioni su un incidente di sicurezza che ha o possa avere ripercussioni sul funzionamento del SIS in uno Stato membro o nell'eu-LISA, o sulla disponibilità, integrità e riservatezza dei dati inseriti o inviati da altri Stati membri o sulle informazioni supplementari scambiate, sono trasmesse senza indugio a tutti gli Stati membri e registrate secondo il piano di gestione degli incidenti stabilito dall'eu-LISA.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Gli Stati membri e l'eu-LISA collaborano qualora si verifichino incidenti di sicurezza.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">La Commissione segnala immediatamente al Parlamento europeo e al Consiglio gli incidenti gravi. Tali segnalazioni sono classificate EU RESTRICTED/RESTREINT UE conformemente alle norme vigenti in materia di sicurezza.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Qualora un incidente di sicurezza sia causato da un uso improprio dei dati, gli Stati membri, Europol e l'Agenzia europea della guardia di frontiera e costiera garantiscono l'imposizione di sanzioni in conformità dell'articolo 59.</div>\n</div>"]]}, "46": {"label": "Articolo 46", "heading": "Distinzione tra persone con caratteristiche simili", "anchor": "art_46", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Quando, inserendo una nuova segnalazione, risulta evidente che nel SIS è già presente una segnalazione nel SIS su una persona che possiede gli stessi elementi di descrizione dell'identità, l'ufficio SIRENE si mette in contatto entro 12 ore con lo Stato membro segnalante, tramite lo scambio di informazioni supplementari, allo scopo di verificare se la segnalazione riguardi o meno la stessa persona.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Se da tale controllo incrociato risulta che la persona oggetto di una nuova segnalazione e quella già inserita nel SIS sono effettivamente la stessa persona, l'ufficio SIRENE applica la procedura per l'inserimento di segnalazioni multiple di cui all'articolo 23.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Qualora la verifica stabilisca che si tratta di due persone diverse, l'ufficio SIRENE convalida la richiesta di inserimento della seconda segnalazione aggiungendo i dati necessari per evitare errori di identificazione.</div>\n</div>"]]}, "47": {"label": "Articolo 47", "heading": "Dati complementari per trattare i casi di usurpazione di identità", "anchor": "art_47", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Quando sono possibili confusioni fra la persona oggetto di una segnalazione e una persona la cui identità è stata usurpata, lo Stato membro segnalante aggiunge alla segnalazione, con il consenso esplicito della persona la cui identità è stata usurpata, dati che la riguardano per evitare le conseguenze negative di un errore di identificazione. La persona la cui identità sia stata usurpata ha il diritto di revocare il proprio consenso al trattamento dei dati personali aggiunti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">I dati relativi alla vittima dell'usurpazione di identità sono usati soltanto ai seguenti fini:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">consentire all'autorità competente di distinguere la persona la cui identità è stata usurpata dalla persona oggetto della segnalazione; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">permettere alla persona la cui identità è stata usurpata di dimostrare la propria identità e di stabilire di essere stata vittima di un'usurpazione di identità.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Ai fini del presente articolo, e previo consenso esplicito della persona la cui identità è stata usurpata per ogni categoria di dati, possono essere inseriti e successivamente trattati nel SIS soltanto i seguenti dati personali della persona la cui identità è stata usurpata:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">cognomi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nomi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nomi e cognomi alla nascita;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nomi e cognomi precedenti e alias, eventualmente registrati a parte;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">segni fisici particolari, oggettivi e inalterabili;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">luogo di nascita;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">data di nascita;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">genere;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">fotografie e immagini del volto;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>j) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">impronte digitali, impronte palmari o entrambe;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>k) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ogni cittadinanza posseduta;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>l) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">categoria dei documenti di identificazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>m) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">paese di rilascio dei documenti di identificazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>n) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">numero dei documenti di identificazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>o) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">data di rilascio dei documenti di identificazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>p) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">indirizzo della persona;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>q) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nome del padre della persona;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>r) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nome della madre della persona.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La Commissione adotta atti di esecuzione al fine di stabilire e sviluppare le norme tecniche necessarie per l'inserimento e il successivo trattamento dei dati di cui al paragrafo 3 del presente articolo. Tali atti di esecuzione sono adottati secondo la procedura d'esame di cui all'articolo 62, paragrafo 2.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">I dati di cui al paragrafo 3 sono cancellati insieme con la segnalazione corrispondente o prima su richiesta dell'interessato.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Possono accedere ai dati di cui al paragrafo 3 soltanto le autorità che hanno diritto di accesso alla segnalazione corrispondente. Esse possono accedervi all'unico scopo di evitare errori di identificazione.</div>\n</div>"]]}, "48": {"label": "Articolo 48", "heading": "Connessioni fra segnalazioni", "anchor": "art_48", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Uno Stato membro può creare una connessione tra le segnalazioni che introduce nel SIS. L'effetto della connessione è instaurare un nesso fra due o più segnalazioni.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La creazione di una connessione non incide sulla specifica azione da intraprendere sulla base di ciascuna segnalazione interconnessa né sul rispettivo periodo di riesame.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La creazione di una connessione non incide sui diritti di accesso previsti dal presente regolamento. Le autorità che non hanno diritto di accesso a talune categorie di segnalazioni non sono in grado di visualizzare la connessione a una segnalazione cui non hanno accesso.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Uno Stato membro crea una connessione tra segnalazioni solo se sussiste un'esigenza operativa.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Qualora uno Stato membro ritenga che la creazione di una connessione tra segnalazioni da parte di un altro Stato membro sia incompatibile con la sua legislazione nazionale o i suoi obblighi internazionali, può adottare le necessarie disposizioni affinché non sia possibile accedere alla connessione dal suo territorio nazionale o per le sue autorità dislocate al di fuori del suo territorio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">La Commissione adotta atti di esecuzione per stabilire e sviluppare norme tecniche necessarie per la connessione tra segnalazioni. Tali atti di esecuzione sono adottati secondo la procedura di esame di cui all'articolo 62, paragrafo 2.</div>\n</div>"]]}, "49": {"label": "Articolo 49", "heading": "Finalità e termini di conservazione delle informazioni supplementari", "anchor": "art_49", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli Stati membri conservano un riferimento alle decisioni che danno origine a una segnalazione presso l'ufficio SIRENE, a sostegno dello scambio di informazioni supplementari.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I dati personali archiviati dall'ufficio SIRENE in seguito allo scambio di informazioni sono conservati soltanto per il tempo necessario a conseguire le finalità per le quali sono stati forniti. Essi sono in ogni caso cancellati entro un anno dalla cancellazione dal SIS della relativa segnalazione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il paragrafo 2 non pregiudica il diritto dello Stato membro di conservare negli archivi nazionali i dati relativi a una determinata segnalazione da esso effettuata o a una segnalazione in collegamento con la quale è stata intrapresa un'azione nel suo territorio. Il periodo per cui tali dati possono essere conservati in tali archivi è disciplinato dalla legislazione nazionale.</div>\n</div>"]]}, "50": {"label": "Articolo 50", "heading": "Trasferimento di dati personali a terzi", "anchor": "art_50", "frags": [[null, "<p class=\"norm\">I dati trattati nel SIS e le relative informazioni supplementari scambiate a norma del presente regolamento non sono trasferiti a paesi terzi o ad organizzazioni internazionali, né sono messi a loro disposizione.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "51": {"label": "Articolo 51", "heading": "Legislazione applicabile", "anchor": "art_51", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il regolamento (UE) 2018/1725 si applica al trattamento dei dati personali da parte dall'eu-LISA e dell'Agenzia europea della guardia di frontiera e costiera in conformità del presente regolamento. Il regolamento (UE) 2016/794 si applica al trattamento dei dati personali da parte di Europol in conformità del presente regolamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il regolamento (UE) 2016/679 si applica al trattamento dei dati personali ai sensi del presente regolamento da parte delle autorità competenti di cui all'articolo 34 del presente regolamento, a eccezione del trattamento a fini di prevenzione, accertamento, indagine, o perseguimento di reati o esecuzione di sanzioni penali, comprese la salvaguardia contro minacce alla sicurezza pubblica e la prevenzione delle stesse, cui si applica la direttiva (UE) 2016/680.</div>\n</div>"]]}, "52": {"label": "Articolo 52", "heading": "Diritto d'informazione", "anchor": "art_52", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">I cittadini di paesi terzi oggetto di una segnalazione nel SIS sono di ciò informati a norma degli articoli 13 e 14 del regolamento (UE) 2016/679 o degli articoli 12 e 13 della direttiva (UE) 2016/680. L'informazione è fornita per iscritto insieme a una copia della decisione nazionale che ha dato origine alla segnalazione di cui all'articolo 24, paragrafo 1, del presente regolamento, o a un riferimento a detta decisione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L'informazione non è fornita laddove la legislazione nazionale consenta che il diritto di informazione sia limitato, in particolare per salvaguardare la sicurezza nazionale, la difesa, la pubblica sicurezza e la prevenzione, l'accertamento, l'indagine e il perseguimento di reati.</div>\n</div>"]]}, "53": {"label": "Articolo 53", "heading": "Diritto di accesso, rettifica di dati inesatti e cancellazione di dati archiviati illecitamente", "anchor": "art_53", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli interessati possono esercitare i diritti di cui agli articoli 15, 16 e 17 del regolamento (UE) 2016/679 e agli articoli 14, nonché 16, paragrafi 1 e 2, della direttiva (UE) 2016/680.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Uno Stato membro diverso dallo Stato membro segnalante può fornire a un interessato le informazioni su qualsiasi dato personale dell'interessato che viene trattatosoltanto se dà prima la possibilità allo Stato membro segnalante di prendere posizione. Alla comunicazione tra gli Stati membri si provvede tramite lo scambio di informazioni supplementari.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Gli Stati membri possono decidere di non fornire informazioni all'interessato, in tutto o in parte, in conformità della legislazione nazionale, nella misura e per il tempo in cui tale limitazione totale o parziale costituisca una misura necessaria e proporzionata in una società democratica, tenuto debito conto dei diritti fondamentali e dei legittimi interessi dell'interessato al fine di:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">non ostacolare indagini, inchieste o procedimenti ufficiali o giudiziari;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">non compromettere la prevenzione, l'accertamento, l'indagine e il perseguimento di reati o l'esecuzione di sanzioni penali;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">proteggere la sicurezza pubblica;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">proteggere la sicurezza nazionale; oppure</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">proteggere i diritti e le libertà altrui.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Nei casi di cui al primo comma, lo Stato membro informa l'interessato, senza ingiustificato ritardo e per iscritto, di ogni rifiuto o limitazione dell'accesso e dei motivi del rifiuto o della limitazione. Dette informazioni possono essere omesse qualora la loro comunicazione rischi di compromettere una delle finalità di cui al primo comma, lettere da a) a e). Lo Stato membro informa l'interessato della possibilità di proporre un reclamo dinanzi a un'autorità di controllo o di proporre ricorso giurisdizionale.</p>"], [null, "<p class=\"norm\">Lo Stato membro fornisce i motivi di fatto o di diritto su cui si basa la decisione di non fornire le informazioni all'interessato. Tali informazioni sono rese disponibili alle autorità di controllo.</p>"], [null, "<p class=\"norm\">In tali casi, l'interessato deve poter esercitare i propri diritti anche tramite le autorità di controllo competenti.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">In seguito a una richiesta di accesso, rettifica o cancellazione, lo Stato membro informa l'interessato non appena possibile e comunque entro i termini di cui all'articolo 12, paragrafo 3, del regolamento (UE) 2016/679 del seguito dato all'esercizio dei diritti di cui al presente articolo, indipendentemente dal fatto che l'interessato sia presente o meno in un paese terzo.</div>\n</div>"]]}, "54": {"label": "Articolo 54", "heading": "Mezzi di impugnazione", "anchor": "art_54", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Fatte salve le disposizioni sui mezzi di impugnazione del regolamento (UE) 2016/679 e della direttiva (UE) 2016/680, chiunque può adire qualsiasi autorità competente, tra cui un organo giurisdizionale, in base alla legislazione di qualsiasi Stato membro, per accedere, rettificare, cancellare, ottenere informazioni o per ottenere un indennizzo relativamente a una segnalazione che lo riguarda.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli Stati membri si impegnano reciprocamente ad eseguire le decisioni definitive emesse dai giudici o dalle autorità di cui al paragrafo 1 del presente articolo, fatto salvo l'articolo 58.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Gli Stati membri presentano relazioni annuali al comitato europeo per la protezione dei dati su:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il numero di richieste di accesso presentate al titolare del trattamento e il numero di casi in cui è stato accordato l'accesso ai dati;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il numero di richieste di accesso presentate all'autorità di controllo e il numero di casi in cui è stato accordato l'accesso ai dati;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il numero di richieste di rettifica di dati inesatti e di cancellazione dei dati archiviati illecitamente che sono state presentate al titolare del trattamento e il numero di casi in cui i dati sono stati rettificati o cancellati;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il numero di richieste di rettifica di dati inesatti e di cancellazioni di dati archiviati illecitamente che sono state presentate all'autorità di controllo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il numero di procedimenti giudiziari avviati;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il numero di cause in cui il giudice ha statuito a favore del ricorrente;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">eventuali osservazioni sui casi di riconoscimento reciproco delle decisioni definitive emesse da giudici o autorità di altri Stati membri in merito a segnalazioni inserite dallo Stato membro segnalante.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Un modello per le relazioni di cui al presente paragrafo è elaborato dalla Commissione.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Le relazioni degli Stati membri sono incluse nella relazione congiunta di cui all'articolo 57, paragrafo 4.</div>\n</div>"]]}, "55": {"label": "Articolo 55", "heading": "Controllo dell'N.SIS", "anchor": "art_55", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ogni Stato membro garantisce che le autorità di controllo indipendenti in esso designate e investite dei poteri di cui al capo VI del regolamento (UE) 2016/679 o al capo VI della direttiva (UE) 2016/680 controllino la liceità del trattamento dei dati personali nel SIS nel territorio di appartenenza e della loro trasmissione da detto territorio, nonché lo scambio e il successivo trattamento di informazioni supplementari nel territorio di appartenenza.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le autorità di controllo provvedono affinché sia svolto un controllo delle operazioni di trattamento dei dati nel rispettivo N.SIS, conformemente alle norme di revisione internazionali, almeno ogni quattro anni. Il controllo è svolto dalle autorità di controllo oppure da queste commissionato direttamente a un revisore per la protezione di dati indipendente. Le autorità di controllo mantengono in qualsiasi momento il controllo sul revisore indipendente e la responsabilità del suo operato.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Gli Stati membri provvedono affinché le rispettive autorità di controllo dispongano delle risorse sufficienti per assolvere i compiti ad esse assegnati a norma del presente regolamento e possano avvalersi della consulenza di persone in possesso di adeguate conoscenze in materia di dati biometrici.</div>\n</div>"]]}, "56": {"label": "Articolo 56", "heading": "Controllo dell'eu-LISA", "anchor": "art_56", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il Garante europeo della protezione dei dati ha il compito di sorvegliare le attività di trattamento dei dati personali da parte dell'eu-LISA e di assicurare che tali attività siano effettuate in conformità del presente regolamento. Si applicano di conseguenza i compiti e le competenze di cui agli articoli 57 e 58 del regolamento (UE) 2018/1725.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il Garante europeo della protezione dei dati svolge un controllo delle attività di trattamento dei dati personali effettuate dall'eu-LISA, conformemente alle norme di revisione internazionali, almeno ogni quattro anni. Una relazione su tale controllo è trasmessa al Parlamento europeo, al Consiglio, all'eu-LISA, alla Commissione e alle autorità di controllo. L'eu-LISA ha l'opportunità di presentare le sue osservazioni prima dell'adozione della relazione.</div>\n</div>"]]}, "57": {"label": "Articolo 57", "heading": "Cooperazione tra le autorità di controllo e il Garante europeo della protezione dei dati", "anchor": "art_57", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le autorità di controllo e il Garante europeo della protezione dei dati, ciascuno nell'ambito delle proprie competenze, cooperano attivamente nel quadro delle rispettive responsabilità e assicurano il controllo coordinato del SIS.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le autorità di controllo e il comitato europeo per la protezione dei dati, ciascuno nell'ambito delle proprie competenze, essi si scambiano informazioni pertinenti, si assistono vicendevolmente nello svolgimento di revisioni e ispezioni, esaminano difficoltà di interpretazione o applicazione del presente regolamento e di altri atti giuridici dell'Unione applicabili, studiano i problemi emersi nell'esercizio di un controllo indipendente o nell'esercizio dei diritti degli interessati, elaborano proposte armonizzate per soluzioni congiunte di eventuali problemi e promuovono la sensibilizzazione del pubblico in materia di diritti di protezione dei dati.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Ai fini di cui al paragrafo 2, le autorità di controllo e il Garante europeo della protezione dei dati si incontrano almeno due volte l'anno nell'ambito del comitato europeo per la protezione dei dati. I costi di tali riunioni e la gestione delle stesse sono a carico del comitato europeo per la protezione dei dati. Nella prima riunione è adottato un regolamento interno. Ulteriori metodi di lavoro sono elaborati congiuntamente, se necessario.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Ogni anno il comitato europeo per la protezione dei dati trasmette al Parlamento europeo, al Consiglio e alla Commissione una relazione congiunta sulle attività inerenti al controllo coordinato.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "58": {"label": "Articolo 58", "heading": "Responsabilità", "anchor": "art_58", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Fatti salvi il diritto al risarcimento e ogni responsabilità ai sensi del regolamento (UE) 2016/679, della direttiva (UE) 2016/680 e del regolamento (UE) 2018/1725:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ogni persona o Stato membro che abbia subito danni materiali o immateriali in conseguenza di un trattamento illecito di dati personali in seguito all'uso dell'N.SIS o di qualsiasi altro atto incompatibile con il presente regolamento compiuti da uno Stato membro ha diritto al risarcimento da parte di tale Stato membro; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ogni persona o Stato membro che abbia subito danni materiali o immateriali in conseguenza di qualsiasi atto incompatibile con il presente regolamento compiuto dall'eu-LISA ha diritto al risarcimento da parte della stessa.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Uno Stato membro o l'eu-LISA sono esonerati in tutto o in parte da tale responsabilità di cui al primo comma se provano che l'evento che ha dato luogo al danno non è loro imputabile.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Uno Stato membro è ritenuto responsabile di ogni eventuale danno arrecato al SIS conseguente all'inosservanza degli obblighi del presente regolamento, fatto salvo il caso e nella misura in cui l'eu-LISA o un altro Stato membro che partecipa al SIS abbiano omesso di adottare provvedimenti ragionevolmente idonei a prevenire il danno o ridurne al minimo l'impatto.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Le azioni proposte contro uno Stato membro per il risarcimento dei danni di cui ai paragrafi 1 e 2 sono disciplinate dalla legislazione nazionale dello Stato membro. Le azioni proposte contro l'eu-LISA per il risarcimento dei danni di cui ai paragrafi 1 e 2 sono soggette alle condizioni previste dai trattati.</div>\n</div>"]]}, "59": {"label": "Articolo 59", "heading": "Sanzioni", "anchor": "art_59", "frags": [[null, "<p class=\"norm\">Gli Stati membri provvedono affinché l'eventuale uso improprio dei dati SIS, od ogni trattamento di tali, o qualsiasi scambio di informazioni supplementari in contrasto con il presente regolamento sia punibile ai sensi della legislazione nazionale.</p>"], [null, "<p class=\"norm\">Le sanzioni previste sono effettive, proporzionate e dissuasive.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "60": {"label": "Articolo 60", "heading": "Controllo e statistiche", "anchor": "art_60", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L'eu-LISA provvede affinché siano attivate procedure atte a controllare il funzionamento del SIS in rapporto agli obiettivi prefissati in termini di risultato, di rapporto costi/benefici, di sicurezza e di qualità del servizio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Ai fini della manutenzione tecnica, delle relazioni, delle relazioni sulla qualità dei dati, e delle statistiche, la eu-LISA ha accesso alle informazioni necessarie riguardanti le operazioni di trattamento effettuate nel SIS centrale.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">L'eu-LISA pubblica statistiche giornaliere, mensili e annuali relative al numero di registrazioni per categoria di segnalazione, sia per ciascuno Stato membro sia su base aggregata. L'eu-LISA pubblica inoltre relazioni annuali relative al numero di riscontri positivi (hit) per categoria di segnalazione, al numero di interrogazioni del SIS e di accessi al SIS per l'inserimento, l'aggiornamento o la cancellazione di una segnalazione sia per ciascuno Stato membro sia su base aggregata. Tali statistiche includono statistiche sugli scambi di informazioni a norma degli articoli da 27 a 31. Le statistiche prodotte non contengono dati personali. La relazione statistica annuale è pubblicata.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Gli Stati membri, Europol e l'Agenzia europea della guardia di frontiera e costiera forniscono all'eu-LISA e alla Commissione le informazioni necessarie per redigere le relazioni di cui ai paragrafi 3, 5, 7 e 8.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">L'eu-LISA trasmette al Parlamento europeo, al Consiglio, agli Stati membri, alla Commissione, a Europol, all'Agenzia europea della guardia di frontiera e costiera nonché al Garante europeo della protezione dei dati tutte le relazioni statistiche che produce.</div>\n</div>"], [null, "<p class=\"norm\">Per controllare l'attuazione degli atti giuridici nell'Unione, anche ai fini del regolamento (UE) n. 1053/2013, la Commissione può chiedere all'eu-LISA di fornire specifiche relazioni statistiche aggiuntive, periodicamente o ad hoc, sulle prestazioni del SIS, sull'uso del SIS e sullo scambio di informazioni supplementari.</p>"], [null, "<p class=\"norm\">L'Agenzia europea della guardia di frontiera e costiera può chiedere all'eu-LISA di fornire specifiche relazioni statistiche aggiuntive, periodicamente o ad hoc, ai fini dello svolgimento di analisi di rischio e valutazioni della vulnerabilità di cui agli articoli 11 e 13 del regolamento (UE) 2016/1624.</p>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Ai fini dell'articolo 15, paragrafo 4, e dei paragrafi 3, 4 e 5 del presente articolo, eu-LISA memorizza nell'archivio centrale di relazioni e statistiche di cui all'articolo 39 del regolamento (UE) 2019/817 i dati di cui all'articolo 15, paragrafo 4, e al paragrafo 3 del presente articolo che non consentono l'identificazione delle persone fisiche.</div>\n</div>"], [null, "<p class=\"norm\">eu-LISA permette alla Commissione e agli organismi di cui paragrafo 5 del presente articolo di ottenere relazioni e statistiche personalizzate. Su richiesta, eu-LISA concede agli Stati membri, alla Commissione, a Europol e all'Agenzia europea della guardia di frontiera e costiera l'accesso all'archivio centrale di relazioni e statistiche in conformità dell'articolo 39 del regolamento (UE) 2019/817.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Due anni dopo la data di applicazione del presente regolamento a norma dell'articolo 66, paragrafo 5, primo comma e successivamente ogni due anni, l'eu-LISA presenta al Parlamento europeo e al Consiglio una relazione sul funzionamento tecnico del SIS centrale e dell'infrastruttura di comunicazione, compresa la loro sicurezza, sull'AFIS e sullo scambio bilaterale e multilaterale di informazioni supplementari fra Stati membri. Una volta la tecnologia in uso, la relazione contiene altresì una valutazione del ricorso alle immagini del volto per accertare l'identità delle persone.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Tre anni dopo la data di applicazione del presente regolamento a norma dell'articolo 66, paragrafo 5, primo comma e successivamente ogni quattro anni, la Commissione svolge una valutazione globale del SIS centrale e dello scambio bilaterale e multilaterale di informazioni supplementari fra Stati membri. Tale valutazione globale comprende un'analisi dei risultati conseguiti in relazione agli obiettivi e una valutazione circa il perdurare della validità dei principi di base, l'applicazione del presente regolamento con riguardo al SIS centrale, la sicurezza del SIS centrale e le eventuali implicazioni per le attività future. La relazione di valutazione comprende altresì una valutazione dell'AFIS e delle campagne d'informazione sul SIS svolte dalla Commissione a norma dell'articolo 19.</div>\n</div>"], [null, "<p class=\"norm\">La relazione di valutazione comprende anche statistiche sul numero di segnalazioni inserite ai sensi dell'articolo 24, paragrafo 1, lettera a) e statistiche sul numero di segnalazioni inserite ai sensi della lettera b) di tale paragrafo. Per quanto riguarda le segnalazioni l'articolo 24, paragrafo 1, lettera a), precisa quante segnalazioni sono state inserite a seguito delle situazioni di cui all'articolo 24, paragrafo 2, lettere a), b) o c). La relazione di valutazione comprende altresì una valutazione dell'applicazione dell'articolo 24 da parte degli Stati membri.</p>"], [null, "<p class=\"norm\">La Commissione trasmette la relazione di valutazione al Parlamento europeo e al Consiglio.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">La Commissione adotta atti di esecuzione per stabilire le modalità dettagliate del funzionamento dell'archivio centrale di cui al paragrafo 6 del presente articolo e le norme sulla protezione dei dati e sulla sicurezza applicabili a tale archivio. Tali atti di esecuzione sono adottati secondo la procedura d'esame di cui all'articolo 62, paragrafo 2.</div>\n</div>"]]}, "61": {"label": "Articolo 61", "heading": "Esercizio della delega", "anchor": "art_61", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il potere di adottare atti delegati è conferito alla Commissione alle condizioni stabilite nel presente articolo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il potere di adottare atti delegati di cui all'articolo 33, paragrafo 4, è conferito alla Commissione per un periodo indeterminato a decorrere dal 27 dicembre 2018.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La delega di potere di cui all'articolo 33, paragrafo 4, può essere revocata in qualsiasi momento dal Parlamento europeo o dal Consiglio. La decisione di revoca pone fine alla delega di potere ivi specificata. Gli effetti della decisione decorrono dal giorno successivo alla pubblicazione della decisione nella <span class=\"italics\">Gazzetta ufficiale dell'Unione europea</span> o da una data successiva ivi specificata. Essa non pregiudica la validità degli atti delegati già in vigore.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Prima dell'adozione dell'atto delegato la Commissione consulta gli esperti designati da ciascuno Stato membro nel rispetto dei principi stabiliti nell'accordo interistituzionale «Legiferare meglio» del 13 aprile 2016.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Non appena adotta un atto delegato, la Commissione ne dà contestualmente notifica al Parlamento europeo e al Consiglio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">L'atto delegato adottato ai sensi dell'articolo 33, paragrafo 4, entra in vigore solo se né il Parlamento europeo né il Consiglio hanno sollevato obiezioni entro il termine di due mesi dalla data in cui esso è stato loro notificato o se, prima della scadenza di tale termine, sia il Parlamento europeo che il Consiglio hanno informato la Commissione che non intendono sollevare obiezioni. Tale termine è prorogato di due mesi su iniziativa del Parlamento europeo o del Consiglio.</div>\n</div>"]]}, "62": {"label": "Articolo 62", "heading": "Procedura di comitato", "anchor": "art_62", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La Commissione è assistita da un comitato. Esso è un comitato ai sensi del regolamento (UE) n. 182/2011.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Nei casi in cui è fatto riferimento al presente paragrafo, si applica l'articolo 5 del regolamento (UE) n. 182/2011.</div>\n</div>"]]}, "63": {"label": "Articolo 63", "heading": "Modifiche al regolamento (CE) n. 1987/2006", "anchor": "art_63", "frags": [[null, "<p class=\"norm\">Il regolamento (CE) n. 1987/2006 è così modificato:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>1) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'articolo 6 è sostituito dal seguente:</p>\n<p class=\"title-article-quoted\">«Articolo 6</p>\n<p class=\"stitle-article-quoted\">Sistemi nazionali</p>\n<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ciascuno Stato membro è competente per l'istituzione, l'esercizio, la manutenzione e l'ulteriore sviluppo del proprio N.SIS II e per il suo collegamento all'NI-SIS.</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Ciascuno Stato membro è responsabile di garantire la disponibilità ininterrotta dei dati SIS II agli utenti finali.»;</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>2) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'articolo 11 è sostituito dal seguente:</p>\n<p class=\"title-article-quoted\">«Articolo 11</p>\n<p class=\"stitle-article-quoted\">Riservatezza – Stati membri</p>\n<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ogni Stato membro applica le proprie norme nazionali in materia di segreto professionale o altri obblighi di riservatezza equivalenti a tutti i soggetti e organismi che debbano lavorare con i dati SIS II e con le informazioni supplementari, conformemente alla propria legislazione nazionale. Tale obbligo vincola tali soggetti e organismi anche dopo che avranno rispettivamente lasciato l'incarico o cessato di lavorare, ovvero portato a termine le proprie attività.</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Se collabora con contraenti esterni per un qualsiasi compito relativo al SIS II, lo Stato membro monitora da vicino le attività del contraente per garantire il rispetto di tutte le disposizioni del presente regolamento, in particolare sulla sicurezza, la riservatezza e la protezione dei dati.</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La gestione operativa dell'N.SIS II o delle copie tecniche non può essere affidata a imprese o organizzazioni private.»;</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>3) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'articolo 15 è così modificato:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è inserito il seguente paragrafo:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«3 <span class=\"italics\">bis</span>.  </span>\n<div class=\"norm inline-element\">L'organo di gestione sviluppa e gestisce un meccanismo e procedure per lo svolgimento dei controlli di qualità sui dati contenuti nel CS-SIS. A tale riguardo, esso riferisce periodicamente agli Stati membri.</div>\n</div>\n<p class=\"norm\">L'organo di gestione riferisce periodicamente alla Commissione in merito ai problemi incontrati, dandone comunicazione anche agli Stati membri interessati.</p>\n<p class=\"norm\">La Commissione riferisce periodicamente al Parlamento europeo e al Consiglio in merito ai problemi di qualità dei dati incontrati.»;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il paragrafo 8 è sostituito dal seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«8.  </span>\n<div class=\"norm inline-element\">La gestione operativa del SIS II centrale consiste nell'insieme dei compiti necessari al funzionamento 24 ore su 24 e 7 giorni su 7 del SIS II centrale, ai sensi del presente regolamento, e comprende in particolare le attività di manutenzione e gli adattamenti tecnici necessari per il buon funzionamento del sistema. Tali compiti comprendono anche il coordinamento, la gestione e il sostegno delle attività di collaudo per il SIS II centrale e i N.SIS II che garantiscono che il SIS II centrale e i N.SIS II operino secondo i requisiti per la conformità tecnica di cui all'articolo 9.»;</div>\n</div>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>4) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all'articolo 17 sono aggiunti i paragrafi seguenti:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«3.  </span>\n<div class=\"norm inline-element\">Se collabora con contraenti esterni per un qualsiasi compito relativo al SIS II, l'organo di gestione monitora da vicino le attività del contraente per garantire il rispetto di tutte le disposizioni del presente regolamento, in particolare sulla sicurezza, la riservatezza e la protezione dei dati.</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La gestione operativa del CS-SIS non può essere affidata a imprese o organizzazioni private.»;</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>5) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all'articolo 20, paragrafo 2, è inserita la lettera seguente:</p>\n<div style=\"margin-left: 48pt; text-indent: -48pt\">\n<p class=\"norm\">«k bis)<span style=\"word-spacing: NaNpt\"> </span>tipo di reato;»;</p>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>6) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all'articolo 21, è aggiunto il paragrafo seguente:</p>\n<p class=\"norm\">«Qualora la decisione di respingimento e di rifiuto di soggiorno di cui all'articolo 24, paragrafo 2, sia connessa a un reato di terrorismo, il caso è ritenuto adeguato, pertinente e sufficientemente importante da giustificare una segnalazione nel SIS II. Per motivi di sicurezza pubblica o nazionale, gli Stati membri possono eccezionalmente astenersi dall'inserire una segnalazione, quando la stessa rischi di ostacolare indagini, inchieste o procedimenti ufficiali o giudiziari.»;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>7) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'articolo 22 è sostituito dal seguente:</p>\n<p class=\"title-article-quoted\">«Articolo 22</p>\n<p class=\"stitle-article-quoted\">Norme specifiche per l'inserimento, la verifica o l'interrogazione tramite fotografie e impronte digitali</p>\n<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Fotografie e impronte digitali possono essere inserite solo previo controllo speciale di qualità per accertare che esse soddisfino gli standard minimi di qualità dei dati. Le specifiche sul controllo speciale di qualità sono stabilite secondo la procedura di cui all'articolo 51, paragrafo 2.</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Qualora siano disponibili dati relativi alle fotografie e alle impronte digitali in una segnalazione nel SIS II, tali dati sono usati per confermare l'identità di una persona reperita grazie all'interrogazione del SIS II con dati alfanumerici.</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">I dati relativi alle impronte digitali possono essere consultati in tutti i casi per identificare una persona. Tuttavia, i dati relativi alle impronte digitali sono consultati per identificare una persona se l'identità della persona non può essere accertata con altri mezzi. A tal fine il SIS II centrale contiene un sistema automatico per il riconoscimento delle impronte digitali (AFIS).</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">I dati relativi alle impronte digitali nel SIS II in relazione a segnalazioni inserite a norma degli articoli 24 e 26 possono essere consultati anche usando serie complete o incomplete di impronte digitali rinvenute sul luogo di un reato grave o di un reato di terrorismo oggetto di indagine, qualora si possa stabilire con un elevato grado di probabilità che tali serie di impronte appartengono a un autore del reato, e purché l'interrogazione sia effettuata simultaneamente nelle pertinenti banche dati nazionali di impronte digitali dello Stato membro.»;</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>8) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'articolo 26 è sostituito dal seguente:</p>\n<p class=\"title-article-quoted\">«Articolo 26</p>\n<p class=\"stitle-article-quoted\">Condizioni per inserire la segnalazione di cittadini di paesi terzi oggetto di provvedimenti restrittivi</p>\n<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le segnalazioni relative a cittadini di paesi terzi oggetto di un provvedimento restrittivo diretto a impedirne l'ingresso o il transito nel territorio degli Stati membri, disposto in conformità di atti giuridici adottati dal Consiglio, compresi i provvedimenti esecutivi di un divieto di viaggio emanato dal Consiglio di sicurezza delle Nazioni Unite, sono inserite nel SIS II, nella misura in cui siano soddisfatte le condizioni relative alla qualità dei dati, ai fini del respingimento e rifiuto di soggiorno.</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le segnalazioni sono inserite, aggiornate e cancellate dall'autorità competente dello Stato membro che esercita la presidenza del Consiglio dell'Unione europea al momento dell'adozione della misura. Se detto Stato membro non ha accesso al SIS II o in caso di segnalazioni inserite a norma del presente regolamento, la competenza spetta allo Stato membro che esercita la presidenza successiva e che ha accesso al SIS II, compreso alle segnalazioni inserite a norma del presente regolamento.</div>\n</div>\n<p class=\"norm\">Gli Stati membri predispongono le procedure necessarie per inserire, aggiornare e cancellare tali segnalazioni.»;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>9) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sono inseriti gli articoli seguenti:</p>\n<p class=\"title-article-quoted\">«Articolo 27 bis</p>\n<p class=\"stitle-article-quoted\">Accesso di Europol ai dati SIS II</p>\n<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L'Agenzia dell'Unione europea per la cooperazione nell'attività di contrasto (Europol), istituita dal regolamento (UE) 2016/794 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">*1</span>\n), ove necessario all'adempimento del suo mandato, ha il diritto di accedere ai dati nel SIS II e di consultarli. Europol può altresì scambiare e richiedere ulteriori informazioni supplementari in conformità delle disposizioni del manuale SIRENE.</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Qualora un'interrogazione effettuata da Europol riveli la presenza di una segnalazione nel SIS II, Europol ne informa lo Stato membro segnalante tramite lo scambio di informazioni supplementari a mezzo dell'infrastruttura di comunicazione e conformemente alle disposizioni del manuale SIRENE. Finché non è in grado di utilizzare le funzionalità previste per lo scambio di informazioni supplementari, Europol informa lo Stato membro segnalante tramite i canali definiti dal regolamento (UE) 2016/794.</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Europol può trattare le informazioni supplementari fornitele dagli Stati membri a fini di raffronto con le proprie banche dati e i progetti di analisi operativa, allo scopo di identificare collegamenti o altri nessi pertinenti e per analisi strategiche, tematiche od operative definite all'articolo 18, paragrafo 2, lettere a), b) e c), del regolamento (UE) 2016/794. Qualsiasi trattamento di informazioni supplementari da parte di Europol ai fini del presente articolo è effettuato in conformità di tale regolamento.</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">L'uso da parte di Europol delle informazioni ottenute tramite un'interrogazione del SIS II o tramite il trattamento di informazioni supplementari è soggetto al consenso dello Stato membro segnalante. Se lo Stato membro acconsente all'uso di tali informazioni, il loro trattamento da parte di Europol è disciplinato dal regolamento (UE) 2016/794. Le informazioni sono trasmesse da Europol a paesi terzi e organismi terzi solo con il consenso dello Stato membro segnalante e nel pieno rispetto della normativa dell'Unione in materia di protezione dei dati.</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Europol:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">fatti salvi i paragrafi 4 e 6, non collega parti del SIS II, né trasferisce i dati in esso contenuti cui ha accesso, a sistemi di raccolta e trattamento di dati gestito da o presso di essa e non scarica o copia altrimenti parti del SIS II;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">in deroga all'articolo 31, paragrafo 1, del regolamento (UE) 2016/794, cancella le informazioni supplementari contenenti dati personali entro un anno dalla cancellazione della relativa segnalazione. A titolo di deroga, se Europol dispone di informazioni nelle proprie banche dati o nei progetti di analisi operativa su un caso cui si riferiscono le informazioni supplementari, Europol può, in via eccezionale, continuare a conservare le informazioni supplementari per svolgere i suoi compiti, ove necessario. Europol informa lo Stato membro segnalante e quello di esecuzione dell'ulteriore conservazione di tali informazioni supplementari e fornisce una giustificazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">limita l'accesso ai dati nel SIS II, comprese le informazioni supplementari, al proprio personale specificamente autorizzato che necessita dell'accesso a tali dati ai fini dell'assolvimento dei propri compiti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">adotta e applica misure per garantire la sicurezza, la riservatezza e l'autocontrollo a norma degli articoli 10, 11 e 13;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">provvede affinché il proprio personale autorizzato a trattare i dati del SIS II riceva una formazione e informazioni adeguate a norma dell'articolo 14;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">fatto salvo il regolamento (UE) 2016/794, consente al Garante europeo della protezione dei dati di sorvegliare ed esaminare le attività da essa svolte nell'esercizio del suo diritto di accesso ai dati nel SIS II e di consultazione degli stessi e nello scambio e nel trattamento di informazioni supplementari.</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Europol può duplicare i dati dal SIS II soltanto per fini tecnici, sempreché tale duplicazione sia necessaria per la consultazione diretta da parte del personale debitamente autorizzato di Europol. Il presente regolamento si applica a tali copie. La copia tecnica è usata soltanto al fine di conservare i dati SIS II mentre tali dati sono consultati. Una volta consultati i dati, la copia è cancellata. Tali usi non sono considerati scaricamento o duplicazione illeciti di dati SIS II. Europol non copia i dati in una segnalazione né i dati complementari trasmessi dagli Stati membri o dal CS-SIS II.</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Per verificare la liceità del trattamento dei dati, per l'autocontrollo e per garantire un'adeguata sicurezza e integrità dei dati, Europol conserva registri di tutti gli accessi al SIS II e le interrogazioni del SIS II in conformità dell'articolo 12. Tali registri e tale documentazione non sono considerati scaricamenti o duplicazioni illeciti di parti del SIS II.</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Gli Stati membri informano Europol, tramite lo scambio di informazioni supplementari, in merito a qualsiasi riscontro positivo (hit) su segnalazioni relative a reati di terrorismo. Gli Stati membri possono eccezionalmente non informare Europol, se ciò comprometterebbe le indagini in corso, la sicurezza di una persona, o sarebbe in contrasto con gli interessi essenziali della sicurezza dello Stato membro segnalante.</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">Il paragrafo 8 si applica a decorrere dalla data in cui Europol è in grado di ricevere informazioni supplementari in conformità del paragrafo 1.</div>\n</div>\n<p class=\"title-article-quoted\">Articolo 27 ter</p>\n<p class=\"stitle-article-quoted\">Accesso ai dati nel SIS II da parte delle squadre della guardia di frontiera e costiera europea, di squadre di personale che assolve compiti attinenti al rimpatrio e dei membri delle squadre di sostegno per la gestione della migrazione</p>\n<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">A norma dell'articolo 40, paragrafo 8, del regolamento (UE) 2016/1624 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">*2</span>\n), i membri delle squadre di cui all'articolo 2, punti 8) e 9), di tale regolamento hanno, nell'ambito dei rispettivi mandati e a condizione che siano autorizzati a effettuare controlli a norma dell'articolo 27, paragrafo 1, del presente regolamento e abbiano ricevuto la formazione necessaria a norma dell'articolo 14 del presente regolamento il diritto di accedere ai dati nel SIS II e di consultarli, nella misura in cui ciò sia necessario per l'assolvimento dei loro compiti e sia richiesto dal piano operativo per un'operazione specifica. L'accesso ai dati nel SIS II non è esteso ad altri membri delle squadre.</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I membri delle squadre di cui al paragrafo 1 esercitano il diritto di accedere ai dati nel SIS II e di consultarli in conformità del paragrafo 1 tramite un'interfaccia tecnica. L'interfaccia tecnica è istituita e gestita dall'Agenzia europea della guardia di frontiera e costiera e permette un collegamento diretto con il SIS II centrale.</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Qualora un'interrogazione effettuata da un membro delle squadre di cui al paragrafo 1 del presente articolo riveli l'esistenza di una segnalazione nel SIS II, lo Stato membro segnalante ne è informato. In conformità dell'articolo 40 del regolamento (UE) 2016/1624, i membri delle squadre intervengono esclusivamente in risposta a una segnalazione nel SIS II sotto il controllo e, di norma, in presenza di guardie di frontiera o di personale che assolve compiti attinenti al rimpatrio dello Stato membro ospitante in cui operano. Lo Stato membro ospitante può autorizzare i membri delle squadre ad agire per suo conto.</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Per verificare la liceità del trattamento dei dati, per l'autocontrollo e per garantire un'adeguata sicurezza e integrità dei dati, l'Agenzia europea della guardia di frontiera e costiera conserva registri di tutti gli accessi al SIS II e le interrogazioni del SIS II in conformità delle disposizioni dell'articolo 12.</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">L'Agenzia europea della guardia di frontiera e costiera adotta e applica misure per garantire la sicurezza, la riservatezza e l'autocontrollo a norma degli articoli 10, 11 e 13 e provvede affinché le squadre di cui al paragrafo 1 del presente articolo applichino tali misure.</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Il presente articolo non pregiudica in alcun modo le disposizioni del regolamento (UE) 2016/1624 concernenti la protezione dei dati né la responsabilità dell'Agenzia europea della guardia di frontiera e costiera per trattamenti non autorizzati o scorretti di tali dati.</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Fatto salvo il paragrafo 2, nessuna parte del SIS II è collegata a un sistema di raccolta e trattamento di dati gestito dalle squadre di cui al paragrafo 1 o dall'Agenzia europea della guardia di frontiera e costiera, e nessun dato nel SIS II a cui hanno accesso tali squadre è trasferito a tale sistema. Nessuna parte del SIS II può essere scaricata o copiata. La registrazione degli accessi e delle interrogazioni non è considerata scaricamento o duplicazione di dati del SIS II.</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">L'Agenzia europea della guardia di frontiera e costiera consente al Garante europeo della protezione dei dati di sorvegliare ed esaminare le attività svolte dalle squadre di cui al presente articolo nell'esercizio del loro diritto di accesso ai dati nel SIS II e di consultazione degli stessi. Ciò non pregiudica le ulteriori disposizioni del regolamento (UE) 2018/1725 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">*3</span>\n).</div>\n</div>\n</div>\n</div>"]]}, "64": {"label": "Articolo 64", "heading": "Modifica della convenzione di applicazione dell'accordo di Schengen", "anchor": "art_64", "frags": [[null, "<p class=\"norm\">L'articolo 25 della convenzione di applicazione dell'accordo di Schengen è soppresso.</p>"]]}, "65": {"label": "Articolo 65", "heading": "Abrogazione", "anchor": "art_65", "frags": [[null, "<p class=\"norm\">Il regolamento (CE) n. 1987/2006 è abrogato a decorrere dalla data di applicazione del presente regolamento di cui al primo comma dell'articolo 66, paragrafo 5.</p>"], [null, "<p class=\"norm\">I riferimenti al regolamento abrogato si intendono fatti al presente regolamento e si leggono secondo la tavola di concordanza di cui all'allegato.</p>"]]}, "66": {"label": "Articolo 66", "heading": "Entrata in vigore, inizio delle attività e applicazione", "anchor": "art_66", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il presente regolamento entra in vigore il ventesimo giorno successivo alla pubblicazione nella <span class=\"italics\">Gazzetta ufficiale dell'Unione europea</span>.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Al più tardi del 28 dicembre 2021 la Commissione adotta una decisione che stabilisce la data alla quale le attività del SIS hanno inizio a norma del presente regolamento, dopo aver verificato che sono soddisfatte le condizioni seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sono stati adottati gli atti di esecuzione necessari per l'applicazione del presente regolamento;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli Stati membri hanno notificato alla Commissione di aver preso le disposizioni tecniche e giuridiche necessarie per trattare i dati SIS e scambiare informazioni supplementari a norma del presente regolamento; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'eu-LISA ha comunicato alla Commissione il positivo completamento di tutte le attività di collaudo relative al CS-SIS e all'interazione tra CS-SIS e N.SIS.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La Commissione controlla attentamente il processo del graduale rispetto delle condizioni di cui al paragrafo 2 e informa il Parlamento europeo e il Consiglio in merito all'esito della verifica di cui a tale paragrafo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Entro il 28 dicembre 2019 e successivamente ogni anno fino all'adozione della decisione della Commissione di cui al paragrafo 2, la Commissione presenta al Parlamento europeo e al Consiglio una relazione sullo stato di avanzamento per la preparazione della piena attuazione del presente regolamento. Tale relazione contiene anche informazioni particolareggiate sulle spese sostenute e sugli eventuali rischi che possono incidere sui costi complessivi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Il presente regolamento si applica a decorrere dalla data stabilita in conformità del paragrafo 2.</div>\n</div>"], [null, "<p class=\"norm inline-element\">In deroga al primo comma:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'articolo 4, paragrafo 4, l'articolo 5, l'articolo 8, paragrafo 4, l'articolo 9, paragrafi 1 e 5, l'articolo 15, paragrafo 7, l'articolo 19, l'articolo 20, paragrafi 3 e 4, l'articolo 32, paragrafo 4, l'articolo 33, paragrafo 4, l'articolo 47, paragrafo 4, l'articolo 48, paragrafo 6, l'articolo 60, paragrafi 6 e 9, l'articolo 61, l'articolo 62, l'articolo 63, punti da 1) a 6) e punto 8), e i paragrafi 3 e 4 del presente articolo si applicano a decorrere dalla data di entrata in vigore del presente regolamento;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'articolo 63, punto 9), si applica a decorrere dal 28 dicembre 2019;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'articolo 63, punto 7), si applica a decorrere dal 28 dicembre 2020.</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">La decisione della Commissione di cui al paragrafo 2 è pubblicata nella <span class=\"italics\">Gazzetta ufficiale dell'Unione europea</span>.</div>\n</div>"], [null, "<p class=\"norm\">Il presente regolamento è obbligatorio in tutti i suoi elementi e direttamente applicabile negli Stati membri conformemente ai trattati.</p>"], [null, "<p>\n<br/>\n</p>"], [null, "<p>\n<br/>\n</p>"]]}}, "recitals": {}};